function makeGoalMilestones(items: Array<[string, boolean, number]>): GoalMilestone[] {
  return items.map(([title, done, weight], index) => ({
    id: `milestone-${index + 1}-${slugify(title)}`,
    title,
    done,
    weight,
  }));
}

