const chineseToneProfiles = {
  0: { name: "light", contour: "neutral", pitch: [46, 46, 44, 44] },
  1: { name: "flat", contour: "55", pitch: [82, 82, 82, 82] },
  2: { name: "rising", contour: "35", pitch: [34, 48, 65, 82] },
  3: { name: "dipping", contour: "214", pitch: [70, 34, 40, 64] },
  4: { name: "falling", contour: "51", pitch: [86, 64, 38, 18] },
} as const;

const chineseToneMarkGroups = [
  { tone: 1, marks: "āēīōūǖĀĒĪŌŪǕ" },
  { tone: 2, marks: "áéíóúǘÁÉÍÓÚǗ" },
  { tone: 3, marks: "ǎěǐǒǔǚǍĚǏǑǓǙ" },
  { tone: 4, marks: "àèìòùǜÀÈÌÒÙǛ" },
];

const chinesePinyinToneMap: Record<string, { base: string; tone: number }> = {
  ā: { base: "a", tone: 1 },
  ē: { base: "e", tone: 1 },
  ī: { base: "i", tone: 1 },
  ō: { base: "o", tone: 1 },
  ū: { base: "u", tone: 1 },
  ǖ: { base: "v", tone: 1 },
  á: { base: "a", tone: 2 },
  é: { base: "e", tone: 2 },
  í: { base: "i", tone: 2 },
  ó: { base: "o", tone: 2 },
  ú: { base: "u", tone: 2 },
  ǘ: { base: "v", tone: 2 },
  ǎ: { base: "a", tone: 3 },
  ě: { base: "e", tone: 3 },
  ǐ: { base: "i", tone: 3 },
  ǒ: { base: "o", tone: 3 },
  ǔ: { base: "u", tone: 3 },
  ǚ: { base: "v", tone: 3 },
  à: { base: "a", tone: 4 },
  è: { base: "e", tone: 4 },
  ì: { base: "i", tone: 4 },
  ò: { base: "o", tone: 4 },
  ù: { base: "u", tone: 4 },
  ǜ: { base: "v", tone: 4 },
  ü: { base: "v", tone: 0 },
};

function getChineseToneNumber(token: string) {
  for (const group of chineseToneMarkGroups) {
    if ([...token].some((mark) => group.marks.includes(mark))) return group.tone;
  }
  return 0;
}

function getChineseToneClass(token: string) {
  return `zh-tone-${getChineseToneNumber(token)}`;
}

function getChineseToneSignal(lesson: ChineseLesson) {
  return lesson.examples
    .flatMap((example) => example.pinyin.replace(/[.,?。？]/g, " ").split(/\s+/))
    .filter(Boolean)
    .slice(0, 9)
    .map((token, index) => {
      const tone = getChineseToneNumber(token) as keyof typeof chineseToneProfiles;
      const profile = chineseToneProfiles[tone];
      const points = profile.pitch
        .map((pitch, pointIndex) => `${(pointIndex / Math.max(profile.pitch.length - 1, 1)) * 100},${100 - pitch}`)
        .join(" ");
      return {
        id: `${token}-${index}`,
        token,
        tone,
        points,
        ...profile,
      };
    });
}

function getChinesePhraseUnits(value: string) {
  return [...value].filter((unit) => !/[，。？！,.?\s]/.test(unit));
}

function getChinesePinyinUnits(value: string) {
  return value.replace(/[.,?。？]/g, " ").split(/\s+/).filter(Boolean);
}

function getChineseMeaningUnits(value: string) {
  return value.replace(/[.,?]/g, " ").split(/\s+/).filter(Boolean).slice(0, 8);
}

function getDefaultChineseReviewState(): ChineseReviewState {
  return {
    ease: 2.5,
    interval: 0,
    repetitions: 0,
    dueDay: CHINESE_TODAY_INDEX,
    totalReviews: 0,
    successfulReviews: 0,
    lapses: 0,
    stability: 0,
    difficulty: 0.5,
  };
}

function getChineseReviewQuality(rating: ChineseReviewRating) {
  return rating === "again" ? 1 : rating === "hard" ? 3 : rating === "ok" ? 4 : 5;
}

function scheduleChineseReview(
  previous: ChineseReviewState | undefined,
  rating: ChineseReviewRating,
  today = CHINESE_TODAY_INDEX,
): ChineseReviewState {
  const current = previous ?? getDefaultChineseReviewState();
  const quality = getChineseReviewQuality(rating);
  const ease = Math.max(
    1.3,
    Number((current.ease + (0.1 - (5 - quality) * (0.08 + (5 - quality) * 0.02))).toFixed(2)),
  );
  const success = quality >= 4;
  const repetitions = success ? current.repetitions + 1 : 0;
  const interval =
    rating === "again"
      ? 0
      : rating === "hard"
      ? Math.max(1, Math.round(Math.max(current.interval, 1) * 1.2))
      : rating === "ok"
        ? current.repetitions === 0
          ? 2
          : current.repetitions === 1
            ? 6
            : Math.max(3, Math.round(Math.max(current.interval, 1) * ease))
        : current.repetitions === 0
          ? 4
          : current.repetitions === 1
            ? 9
            : Math.max(5, Math.round(Math.max(current.interval, 1) * (ease + 0.85)));
  const totalReviews = current.totalReviews + 1;
  const successfulReviews = current.successfulReviews + (success ? 1 : 0);
  const lapses = current.lapses + (rating === "again" ? 1 : 0);
  const stability = Math.max(0, Math.round(interval * ease));
  const difficulty = Math.min(
    0.96,
    Math.max(0.08, Number((current.difficulty + (rating === "again" ? 0.16 : rating === "hard" ? 0.08 : rating === "easy" ? -0.05 : -0.02)).toFixed(2))),
  );

  return {
    ease,
    interval,
    repetitions,
    dueDay: today + interval,
    lastReviewedDay: today,
    totalReviews,
    successfulReviews,
    lapses,
    stability,
    difficulty,
    rating,
  };
}

function getChineseRetention(state: ChineseReviewState, today = CHINESE_TODAY_INDEX) {
  if (!state.totalReviews) return 0;
  if (state.interval === 0) return state.rating === "again" ? 18 : 42;
  const elapsed = Math.max(0, today - (state.lastReviewedDay ?? today));
  const stability = Math.max(state.stability, state.interval, 1);
  return Math.max(0, Math.min(99, Math.round(100 * Math.exp(-elapsed / stability))));
}

function getChineseReviewStatus(state: ChineseReviewState, today = CHINESE_TODAY_INDEX) {
  if (!state.totalReviews) return "NEW";
  if (state.dueDay < today) return "LATE";
  if (state.dueDay === today || state.interval <= 1) return "DUE";
  if (state.dueDay - today <= 3) return "SOON";
  return "OK";
}

function getChineseDueLabel(state: ChineseReviewState, today = CHINESE_TODAY_INDEX) {
  if (!state.totalReviews) return "new";
  const delta = state.dueDay - today;
  if (delta < 0) return `${Math.abs(delta)}d late`;
  if (delta === 0) return "due now";
  return `D+${delta}`;
}

function getChineseReviewUnlockKey(day: number, status: ChineseLoadForecastStatus) {
  return `D${String(day).padStart(3, "0")}:${status}`;
}

function isChineseRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null && !Array.isArray(value);
}

function getChineseNumber(value: unknown, fallback: number) {
  const number = Number(value);
  return Number.isFinite(number) ? number : fallback;
}

function getChineseClampedNumber(value: unknown, fallback: number, min: number, max: number) {
  return Math.min(max, Math.max(min, getChineseNumber(value, fallback)));
}

function getChineseStoredDay(value: unknown) {
  return Math.min(Math.max(Math.trunc(getChineseNumber(value, CHINESE_TODAY_INDEX)), 1), CHINESE_PRACTICE_TOTAL_DAYS);
}

function isChineseReviewRating(value: unknown): value is ChineseReviewRating {
  return value === "again" || value === "hard" || value === "ok" || value === "easy";
}

function isChinesePlacementStatus(value: unknown): value is ChinesePlacementProfile["status"] {
  return value === "sample" || value === "steady" || value === "advance" || value === "repair";
}

function isChineseCoachBriefingMode(value: unknown): value is ChineseCoachBriefing["mode"] {
  return value === "sample" || value === "repair" || value === "review" || value === "voice" || value === "placement" || value === "forecast" || value === "flow";
}

function isChineseMissLedgerSource(value: unknown): value is ChineseMissLedgerSource {
  return value === "pinyin" || value === "voice" || value === "srs";
}

function isChineseMissFollowUpOutcomeStatus(value: unknown): value is ChineseMissFollowUpOutcomeStatus {
  return value === "waiting" || value === "improved" || value === "stable" || value === "hot";
}

function isChineseMissFollowUpResolvedStatus(value: unknown): value is ChineseMissFollowUpResolvedStatus {
  return value === "improved" || value === "stable" || value === "hot";
}

function isChineseLoadForecastStatus(value: unknown): value is ChineseLoadForecastStatus {
  return value === "light" || value === "steady" || value === "heavy" || value === "overload";
}

function getChineseStoredReviewState(value: unknown): ChineseReviewState | null {
  if (!isChineseRecord(value)) return null;
  const fallback = getDefaultChineseReviewState();
  const rating = isChineseReviewRating(value.rating) ? value.rating : undefined;
  return {
    ease: getChineseNumber(value.ease, fallback.ease),
    interval: getChineseNumber(value.interval, fallback.interval),
    repetitions: getChineseNumber(value.repetitions, fallback.repetitions),
    dueDay: getChineseNumber(value.dueDay, fallback.dueDay),
    lastReviewedDay: value.lastReviewedDay === undefined ? undefined : getChineseNumber(value.lastReviewedDay, CHINESE_TODAY_INDEX),
    totalReviews: getChineseNumber(value.totalReviews, fallback.totalReviews),
    successfulReviews: getChineseNumber(value.successfulReviews, fallback.successfulReviews),
    lapses: getChineseNumber(value.lapses, fallback.lapses),
    stability: getChineseNumber(value.stability, fallback.stability),
    difficulty: getChineseNumber(value.difficulty, fallback.difficulty),
    rating,
  };
}

function getChineseStoredStringArray(value: unknown) {
  return Array.isArray(value) ? value.filter((item): item is string => typeof item === "string") : [];
}

function getChineseStoredSpeechAttempt(value: unknown): ChineseSpeechAttempt | null {
  if (!isChineseRecord(value)) return null;
  const cardId = typeof value.cardId === "string" ? value.cardId : "";
  const phrase = typeof value.phrase === "string" ? value.phrase : "";
  if (!cardId || !phrase) return null;
  const rating = isChineseReviewRating(value.rating) ? value.rating : undefined;
  return {
    id: typeof value.id === "string" ? value.id : `${cardId}-${typeof value.createdAt === "string" ? value.createdAt : "voice"}`,
    cardId,
    phrase,
    transcript: typeof value.transcript === "string" ? value.transcript : "",
    score: getChineseClampedNumber(value.score, 0, 0, 100),
    confidence: getChineseClampedNumber(value.confidence, 0, 0, 100),
    matched: getChineseClampedNumber(value.matched, 0, 0, 99),
    total: Math.max(1, Math.trunc(getChineseNumber(value.total, 1))),
    createdAt: typeof value.createdAt === "string" ? value.createdAt : new Date().toISOString(),
    rating,
  };
}

function getChineseStoredRepairHistoryEntry(value: unknown): ChineseRepairHistoryEntry | null {
  if (!isChineseRecord(value)) return null;
  const missionKey = typeof value.missionKey === "string" ? value.missionKey : "";
  if (!missionKey) return null;
  const symbols = getChineseStoredStringArray(value.symbols).slice(0, 4);
  return {
    id: typeof value.id === "string" ? value.id : `${missionKey}-history`,
    missionKey,
    completedAt: typeof value.completedAt === "string" ? value.completedAt : new Date().toISOString(),
    day: getChineseStoredDay(value.day),
    tone: Math.trunc(getChineseClampedNumber(value.tone, 0, 0, 4)),
    toneName: typeof value.toneName === "string" ? value.toneName : "tone",
    symbols,
    score: getChineseClampedNumber(value.score, 100, 0, 100),
    summary: typeof value.summary === "string" ? value.summary : "repair locked",
  };
}

function getChineseStoredPlacementHistoryEntry(value: unknown): ChinesePlacementHistoryEntry | null {
  if (!isChineseRecord(value)) return null;
  const createdAt = typeof value.createdAt === "string" ? value.createdAt : "";
  const hskLabel = typeof value.hskLabel === "string" ? value.hskLabel : "";
  if (!createdAt || !hskLabel) return null;
  return {
    id: typeof value.id === "string" ? value.id : `${createdAt}-placement`,
    createdAt,
    fromDay: getChineseStoredDay(value.fromDay),
    toDay: getChineseStoredDay(value.toDay),
    status: isChinesePlacementStatus(value.status) ? value.status : "steady",
    hskLabel,
    readiness: getChineseClampedNumber(value.readiness, 0, 0, 100),
    confidence: getChineseClampedNumber(value.confidence, 0, 0, 100),
    action: typeof value.action === "string" ? value.action : "hold day",
    summary: typeof value.summary === "string" ? value.summary : "placement decision logged",
  };
}

function getChineseStoredCoachHistoryBaseline(value: unknown): ChineseCoachHistoryBaseline {
  const record: Record<string, unknown> = isChineseRecord(value) ? value : {};
  return {
    reviewed: Math.max(0, Math.trunc(getChineseNumber(record.reviewed, 0))),
    due: Math.max(0, Math.trunc(getChineseNumber(record.due, 0))),
    accuracy: getChineseClampedNumber(record.accuracy, 0, 0, 100),
    retention: getChineseClampedNumber(record.retention, 0, 0, 100),
    voiceAverage: getChineseClampedNumber(record.voiceAverage, 0, 0, 100),
    repairDelta: Math.round(getChineseNumber(record.repairDelta, 0)),
    placementReadiness: getChineseClampedNumber(record.placementReadiness, 0, 0, 100),
    placementConfidence: getChineseClampedNumber(record.placementConfidence, 0, 0, 100),
    placementWeeklyDelta: Math.round(getChineseNumber(record.placementWeeklyDelta, 0)),
    forecastPeakLoad: Math.max(0, Math.trunc(getChineseNumber(record.forecastPeakLoad, 0))),
    forecastAverageLoad: Math.max(0, Math.trunc(getChineseNumber(record.forecastAverageLoad, 0))),
    xp: Math.max(0, Math.trunc(getChineseNumber(record.xp, 0))),
    combo: Math.max(0, Math.trunc(getChineseNumber(record.combo, 0))),
  };
}

function getChineseStoredReviewUnlockEntry(value: unknown): ChineseReviewUnlockEntry | null {
  if (!isChineseRecord(value)) return null;
  const key = typeof value.key === "string" ? value.key : "";
  if (!key) return null;
  return {
    id: typeof value.id === "string" ? value.id : `${key}-unlock`,
    key,
    createdAt: typeof value.createdAt === "string" ? value.createdAt : new Date().toISOString(),
    day: getChineseStoredDay(value.day),
    status: isChineseLoadForecastStatus(value.status) ? value.status : "steady",
    reviewedCards: Math.max(0, Math.trunc(getChineseNumber(value.reviewedCards, 0))),
    target: Math.max(1, Math.trunc(getChineseNumber(value.target, 1))),
    peakLoad: Math.max(0, Math.trunc(getChineseNumber(value.peakLoad, 0))),
    summary: typeof value.summary === "string" ? value.summary : "review gate cleared",
  };
}

function getChineseStoredMissDrillHistoryEntry(value: unknown): ChineseMissDrillHistoryEntry | null {
  if (!isChineseRecord(value)) return null;
  const signalId = typeof value.signalId === "string" ? value.signalId : "";
  const hanzi = typeof value.hanzi === "string" ? value.hanzi : "";
  const pinyin = typeof value.pinyin === "string" ? value.pinyin : "";
  if (!signalId || !hanzi || !pinyin) return null;
  const sources = Array.isArray(value.sources) ? value.sources.filter(isChineseMissLedgerSource) : [];

  return {
    id: typeof value.id === "string" ? value.id : `${signalId}-miss-drill`,
    signalId,
    hanzi,
    pinyin,
    sources,
    risk: getChineseClampedNumber(value.risk, 0, 0, 100),
    completedAt: typeof value.completedAt === "string" ? value.completedAt : new Date().toISOString(),
    score: getChineseClampedNumber(value.score, 100, 0, 100),
  };
}

function getChineseStoredMissFollowUpTrendPoint(
  value: unknown,
  fallbackSignalId: string,
): ChineseMissFollowUpTrendPoint | null {
  if (!isChineseRecord(value)) return null;
  if (!isChineseMissFollowUpResolvedStatus(value.status)) return null;

  return {
    id:
      typeof value.id === "string" && value.id
        ? value.id
        : `${fallbackSignalId}-trend-${getChineseStoredDay(value.day)}-${value.status}`,
    day: getChineseStoredDay(value.day),
    status: value.status,
    delta: Math.round(getChineseClampedNumber(value.delta, 0, -100, 100)),
    risk: getChineseClampedNumber(value.risk, 0, 0, 100),
    sources: Array.isArray(value.sources) ? value.sources.filter(isChineseMissLedgerSource) : [],
  };
}

function getChineseStoredMissDrillFollowUpEntry(value: unknown): ChineseMissDrillFollowUpEntry | null {
  if (!isChineseRecord(value)) return null;
  const signalId = typeof value.signalId === "string" ? value.signalId : "";
  const hanzi = typeof value.hanzi === "string" ? value.hanzi : "";
  const pinyin = typeof value.pinyin === "string" ? value.pinyin : "";
  if (!signalId || !hanzi || !pinyin) return null;
  const sources = Array.isArray(value.sources) ? value.sources.filter(isChineseMissLedgerSource) : [];
  const createdDay = getChineseStoredDay(value.createdDay);
  const interval = Math.max(1, Math.trunc(getChineseClampedNumber(value.interval, 1, 1, 30)));
  const risk = getChineseClampedNumber(value.risk, 0, 0, 100);
  const baselineRisk = getChineseClampedNumber(value.baselineRisk, risk, 0, 100);
  const lastCompletedDay = getChineseStoredDay(value.lastCompletedDay ?? createdDay);
  const lastOutcome = isChineseMissFollowUpOutcomeStatus(value.lastOutcome) ? value.lastOutcome : "waiting";
  const lastDelta = Math.round(getChineseClampedNumber(value.lastDelta, 0, -100, 100));
  const lastSignalRisk = getChineseClampedNumber(value.lastSignalRisk, risk, 0, 100);
  const lastSources = Array.isArray(value.lastSources) ? value.lastSources.filter(isChineseMissLedgerSource) : sources;
  const storedOutcomeHistory = (Array.isArray(value.outcomeHistory) ? value.outcomeHistory : [])
    .map((entry) => getChineseStoredMissFollowUpTrendPoint(entry, signalId))
    .filter((entry): entry is ChineseMissFollowUpTrendPoint => Boolean(entry));
  const migratedOutcomeHistory =
    storedOutcomeHistory.length || !isChineseMissFollowUpResolvedStatus(lastOutcome)
      ? storedOutcomeHistory
      : [
          {
            id: `${signalId}-trend-${lastCompletedDay}-${lastOutcome}`,
            day: lastCompletedDay,
            status: lastOutcome,
            delta: lastDelta,
            risk: lastSignalRisk,
            sources: lastSources,
          },
        ];

  return {
    id: typeof value.id === "string" ? value.id : `${signalId}-follow-up`,
    signalId,
    hanzi,
    pinyin,
    sources,
    risk,
    baselineRisk,
    createdDay,
    dueDay: getChineseStoredDay(value.dueDay ?? createdDay + interval),
    interval,
    attempts: Math.max(0, Math.trunc(getChineseNumber(value.attempts, 0))),
    lastCompletedDay,
    lastOutcome,
    lastDelta,
    lastSignalRisk,
    lastSources,
    outcomeHistory: migratedOutcomeHistory.slice(0, CHINESE_MISS_FOLLOW_UP_TREND_LIMIT),
  };
}

function getChineseMissFollowUpInterval(
  signal: Pick<ChineseMissedCharacterSignal, "risk" | "sources">,
  attempts = 0,
) {
  const base = signal.risk >= 90 || signal.sources.includes("srs") ? 1 : signal.risk >= 75 || signal.sources.includes("voice") ? 2 : 3;
  return Math.min(21, base + Math.max(0, attempts) * 2);
}

function getChineseMissFollowUpDueLabel(entry: ChineseMissDrillFollowUpEntry, day: number) {
  const delta = entry.dueDay - day;
  if (delta < 0) return `${Math.abs(delta)}d late`;
  if (delta === 0) return "due now";
  return `D+${delta}`;
}

function getChineseMissFollowUpSignal(entry: ChineseMissDrillFollowUpEntry): ChineseMissedCharacterSignal {
  return {
    id: entry.signalId,
    hanzi: entry.hanzi,
    pinyin: entry.pinyin,
    sources: entry.sources,
    risk: entry.risk,
    count: entry.attempts + 1,
    detail: `D${String(entry.dueDay).padStart(3, "0")} follow-up`,
    action: "rerun micro drill",
  };
}

function getChineseMissFollowUpOutcome(
  entry: ChineseMissDrillFollowUpEntry,
  currentSignal?: ChineseMissedCharacterSignal,
): ChineseMissFollowUpOutcome {
  const afterRisk = currentSignal?.risk ?? 0;
  const afterSources = currentSignal?.sources ?? [];
  const delta = entry.baselineRisk - afterRisk;
  const clearedSources = entry.sources.filter((source) => !afterSources.includes(source)).length;
  const addedSources = afterSources.filter((source) => !entry.sources.includes(source)).length;
  const status: ChineseMissFollowUpOutcomeStatus =
    afterRisk === 0 || delta >= 20 || clearedSources >= 2
      ? "improved"
      : afterRisk >= entry.baselineRisk - 5 || addedSources > 0
        ? "hot"
        : "stable";
  const label =
    status === "improved"
      ? "improved"
      : status === "hot"
        ? "still hot"
        : "stable";

  return {
    status,
    label,
    delta,
    afterRisk,
    afterSources,
  };
}

function getChineseMissFollowUpTrend(entry: ChineseMissDrillFollowUpEntry) {
  return [...entry.outcomeHistory]
    .slice(0, CHINESE_MISS_FOLLOW_UP_TREND_LIMIT)
    .reverse();
}

function getChineseMissFollowUpTrendHeight(point: ChineseMissFollowUpTrendPoint) {
  if (point.status === "improved") return Math.max(28, Math.min(100, 28 + Math.max(point.delta, 0)));
  if (point.status === "hot") return Math.max(36, Math.min(100, point.risk));
  return Math.max(26, Math.min(72, 42 + Math.abs(point.delta)));
}

function getChineseMissFollowUpTrendLabel(entry: ChineseMissDrillFollowUpEntry) {
  const points = getChineseMissFollowUpTrend(entry);
  if (!points.length) return "trend pending";
  const improved = points.filter((point) => point.status === "improved").length;
  const hot = points.filter((point) => point.status === "hot").length;
  if (hot > improved) return `${hot} hot return${hot === 1 ? "" : "s"}`;
  if (improved > hot) return `${improved} cooled return${improved === 1 ? "" : "s"}`;
  return `${points.length} mixed return${points.length === 1 ? "" : "s"}`;
}

function getChineseStoredCoachHistoryEntry(value: unknown): ChineseCoachHistoryEntry | null {
  if (!isChineseRecord(value)) return null;
  const packetId = typeof value.packetId === "string" ? value.packetId : "";
  const title = typeof value.title === "string" ? value.title : "";
  if (!packetId || !title) return null;
  return {
    id: typeof value.id === "string" ? value.id : `${packetId}-coach`,
    createdAt: typeof value.createdAt === "string" ? value.createdAt : new Date().toISOString(),
    packetId,
    mode: isChineseCoachBriefingMode(value.mode) ? value.mode : "flow",
    signal: typeof value.signal === "string" ? value.signal : "coach",
    title,
    command: typeof value.command === "string" ? value.command : "continue",
    day: getChineseStoredDay(value.day),
    activeWord: typeof value.activeWord === "string" ? value.activeWord : "",
    baseline: getChineseStoredCoachHistoryBaseline(value.baseline),
  };
}

function loadChineseMemorySnapshot(): ChineseMemorySnapshot | null {
  try {
    const raw = window.localStorage.getItem(CHINESE_MEMORY_STORAGE_KEY);
    if (!raw) return null;
    const parsed = JSON.parse(raw) as unknown;
    if (!isChineseRecord(parsed)) return null;
    const reviewRatings = Object.entries(isChineseRecord(parsed.reviewRatings) ? parsed.reviewRatings : {}).reduce<Record<string, ChineseReviewState>>(
      (ratings, [cardId, value]) => {
        const state = getChineseStoredReviewState(value);
        if (state) ratings[cardId] = state;
        return ratings;
      },
      {},
    );
    return {
      version: 1,
      savedAt: typeof parsed.savedAt === "string" ? parsed.savedAt : "",
      selectedPracticeDay: getChineseStoredDay(parsed.selectedPracticeDay),
      sessionXp: getChineseNumber(parsed.sessionXp, 0),
      reviewCombo: getChineseNumber(parsed.reviewCombo, 0),
      reviewRatings,
      completedDrills: getChineseStoredStringArray(parsed.completedDrills),
      completedRepairDrills: getChineseStoredStringArray(parsed.completedRepairDrills),
      repairHistory: (Array.isArray(parsed.repairHistory) ? parsed.repairHistory : [])
        .map(getChineseStoredRepairHistoryEntry)
        .filter((entry): entry is ChineseRepairHistoryEntry => Boolean(entry))
        .slice(0, 21),
      placementHistory: (Array.isArray(parsed.placementHistory) ? parsed.placementHistory : [])
        .map(getChineseStoredPlacementHistoryEntry)
        .filter((entry): entry is ChinesePlacementHistoryEntry => Boolean(entry))
        .slice(0, 21),
      coachHistory: (Array.isArray(parsed.coachHistory) ? parsed.coachHistory : [])
        .map(getChineseStoredCoachHistoryEntry)
        .filter((entry): entry is ChineseCoachHistoryEntry => Boolean(entry))
        .slice(0, CHINESE_COACH_HISTORY_LIMIT),
      reviewUnlocks: (Array.isArray(parsed.reviewUnlocks) ? parsed.reviewUnlocks : [])
        .map(getChineseStoredReviewUnlockEntry)
        .filter((entry): entry is ChineseReviewUnlockEntry => Boolean(entry))
        .slice(0, 21),
      completedMissDrills: getChineseStoredStringArray(parsed.completedMissDrills),
      missDrillHistory: (Array.isArray(parsed.missDrillHistory) ? parsed.missDrillHistory : [])
        .map(getChineseStoredMissDrillHistoryEntry)
        .filter((entry): entry is ChineseMissDrillHistoryEntry => Boolean(entry))
        .slice(0, CHINESE_MISS_DRILL_HISTORY_LIMIT),
      missDrillFollowUps: (Array.isArray(parsed.missDrillFollowUps) ? parsed.missDrillFollowUps : [])
        .map(getChineseStoredMissDrillFollowUpEntry)
        .filter((entry): entry is ChineseMissDrillFollowUpEntry => Boolean(entry))
        .slice(0, CHINESE_MISS_FOLLOW_UP_LIMIT),
      strokeMatrixDone: getChineseStoredStringArray(parsed.strokeMatrixDone),
      speechAttempts: (Array.isArray(parsed.speechAttempts) ? parsed.speechAttempts : [])
        .map(getChineseStoredSpeechAttempt)
        .filter((attempt): attempt is ChineseSpeechAttempt => Boolean(attempt))
        .slice(0, CHINESE_SPEECH_HISTORY_LIMIT),
    };
  } catch {
    return null;
  }
}

function saveChineseMemorySnapshot(snapshot: ChineseMemorySnapshot) {
  try {
    window.localStorage.setItem(CHINESE_MEMORY_STORAGE_KEY, JSON.stringify(snapshot));
    return true;
  } catch {
    return false;
  }
}

function getChineseDictionaryEntry(token: string, fallback?: { pinyin?: string; meaning?: string; note?: string }): ChineseDictionaryEntry {
  const rawToken = token.trim();
  const cleanToken =
    chineseDictionary[rawToken] || chinesePracticeWordIndex[rawToken]
      ? rawToken
      : getChinesePhraseUnits(token)[0] ?? rawToken;
  const practiceWord = chinesePracticeWordIndex[cleanToken];
  const practiceUnits = practiceWord ? getChinesePhraseUnits(practiceWord.hanzi) : [];
  return (
    chineseDictionary[cleanToken] ??
    (practiceWord
      ? {
          hanzi: practiceWord.hanzi,
          pinyin: practiceWord.pinyin,
          meaning: practiceWord.meaning,
          radical: practiceUnits[0] ?? practiceWord.hanzi,
          strokeCount: Math.max(1, practiceUnits.length * 5),
          hsk: practiceWord.hsk,
          frequency: 900 + practiceWord.hsk * 120,
          components: practiceUnits.length > 1 ? practiceUnits.slice(0, 4) : [practiceWord.hanzi],
          etymology: `Practice-bank entry tagged ${practiceWord.tags.join(", ")}.`,
          words: [],
        }
      : {
          hanzi: cleanToken,
          pinyin: fallback?.pinyin ?? "unknown",
          meaning: fallback?.meaning ?? "add to dictionary",
          radical: cleanToken,
          strokeCount: Math.max(1, cleanToken.codePointAt(0) ? String(cleanToken.codePointAt(0)).length : 1),
          hsk: 6,
          frequency: 3000,
          components: [cleanToken],
          etymology: fallback?.note ?? "No local entry yet. This card can still be practiced and reviewed.",
          words: [],
        })
  );
}

function getChineseStrokePlan(entry: ChineseDictionaryEntry) {
  const count = Math.max(1, Math.min(entry.strokeCount, 8));
  return Array.from({ length: count }, (_, index) => {
    const x1 = 18 + ((index * 17) % 58);
    const y1 = 20 + ((index * 23) % 54);
    const x2 = Math.min(88, x1 + 24 + (index % 2) * 10);
    const y2 = Math.min(86, y1 + (index % 3 === 0 ? 0 : 20));
    return {
      id: `${entry.hanzi}-stroke-${index + 1}`,
      label: `S${String(index + 1).padStart(2, "0")}`,
      points: `${x1},${y1} ${x2},${y2}`,
    };
  });
}

function getChineseCardCharacters(card: { hanzi: string }) {
  return Array.from(new Set(getChinesePhraseUnits(card.hanzi)));
}

function getChineseSpeechUnits(value: string) {
  return Array.from(value).filter((unit) => /[\u3400-\u9fff]/.test(unit));
}

function getChineseLcsCount(source: string[], target: string[]) {
  const rows = source.length + 1;
  const cols = target.length + 1;
  const matrix = Array.from({ length: rows }, () => Array.from({ length: cols }, () => 0));

  for (let row = 1; row < rows; row += 1) {
    for (let col = 1; col < cols; col += 1) {
      matrix[row][col] =
        source[row - 1] === target[col - 1]
          ? matrix[row - 1][col - 1] + 1
          : Math.max(matrix[row - 1][col], matrix[row][col - 1]);
    }
  }

  return matrix[source.length][target.length];
}

function scoreChineseSpeech(expected: string, transcript: string) {
  const expectedUnits = getChineseSpeechUnits(expected);
  const transcriptUnits = getChineseSpeechUnits(transcript);
  const total = Math.max(expectedUnits.length, 1);
  const positionMatches = expectedUnits.reduce((count, unit, index) => count + (transcriptUnits[index] === unit ? 1 : 0), 0);
  const lcsMatches = getChineseLcsCount(expectedUnits, transcriptUnits);
  const coverage = Math.min(transcriptUnits.length / total, 1);
  const score = Math.round(((positionMatches / total) * 0.55 + (lcsMatches / total) * 0.35 + coverage * 0.1) * 100);

  return {
    score: Math.min(100, score),
    matched: lcsMatches,
    total,
  };
}

function getChineseSentencePattern(phrase: string) {
  if (phrase.includes("在")) return "progressive 在 pattern";
  if (phrase.includes("吗")) return "question-final 吗";
  if (/[一二三四五六七八九十零两]/.test(phrase)) return "number phrase";
  if (getChineseSpeechUnits(phrase).length <= 2) return "single-word recall";
  return "core sentence";
}

function getChineseVoiceWeaknesses(attempts: ChineseSpeechAttempt[]) {
  const grouped = attempts.reduce<Record<string, { hanzi: string; pattern: string; attempts: number; scoreTotal: number }>>((weaknesses, attempt) => {
    if (attempt.score >= 82) return weaknesses;
    const expectedUnits = getChineseSpeechUnits(attempt.phrase);
    const transcriptUnits = getChineseSpeechUnits(attempt.transcript);
    const weakUnits = expectedUnits.filter((unit, index) => transcriptUnits[index] !== unit || !transcriptUnits.includes(unit));
    const units = weakUnits.length ? weakUnits : expectedUnits;
    const pattern = getChineseSentencePattern(attempt.phrase);

    units.forEach((hanzi) => {
      const id = `${hanzi}-${pattern}`;
      const existing = weaknesses[id] ?? { hanzi, pattern, attempts: 0, scoreTotal: 0 };
      weaknesses[id] = {
        ...existing,
        attempts: existing.attempts + 1,
        scoreTotal: existing.scoreTotal + attempt.score,
      };
    });

    return weaknesses;
  }, {});

  return Object.entries(grouped)
    .map<ChineseVoiceWeakness>(([id, weakness]) => {
      const entry = getChineseDictionaryEntry(weakness.hanzi);
      const averageScore = Math.round(weakness.scoreTotal / Math.max(weakness.attempts, 1));
      return {
        id,
        hanzi: weakness.hanzi,
        pinyin: entry.pinyin,
        pattern: weakness.pattern,
        attempts: weakness.attempts,
        averageScore,
        repair: `${weakness.hanzi} x5 · shadow full phrase`,
      };
    })
    .sort((a, b) => a.averageScore - b.averageScore || b.attempts - a.attempts)
    .slice(0, 3);
}

function getChinesePhrasePinyinForSpeech(phrase: string) {
  const lessonExample = chineseLessons
    .flatMap((lesson) => lesson.examples)
    .find((example) => example.hanzi === phrase);
  if (lessonExample) return getChinesePinyinUnits(lessonExample.pinyin);
  return getChineseSpeechUnits(phrase).map((unit) => getChineseDictionaryEntry(unit).pinyin);
}

function getChineseVoiceHeatmap(attempts: ChineseSpeechAttempt[]) {
  const recentAttempts = attempts.slice(0, 30);
  const toneOrder = [1, 2, 3, 4, 0];
  const toneStats = toneOrder.reduce<
    Record<number, { tone: number; exposure: number; misses: number; scoreTotal: number; sample: string; name: string }>
  >((stats, tone) => {
    const rail = chineseToneRails.find((item) => Number(item.label) === tone);
    const profile = chineseToneProfiles[tone as keyof typeof chineseToneProfiles] ?? chineseToneProfiles[0];
    stats[tone] = {
      tone,
      exposure: 0,
      misses: 0,
      scoreTotal: 0,
      sample: rail?.sample ?? (tone === 0 ? "ma" : "mā"),
      name: profile.name,
    };
    return stats;
  }, {});
  const hanziStats: Record<string, { hanzi: string; pinyin: string; exposure: number; misses: number }> = {};

  recentAttempts.forEach((attempt) => {
    const expectedUnits = getChineseSpeechUnits(attempt.phrase);
    const transcriptUnits = getChineseSpeechUnits(attempt.transcript);
    const pinyinUnits = getChinesePhrasePinyinForSpeech(attempt.phrase);

    expectedUnits.forEach((hanzi, index) => {
      const pinyin = pinyinUnits[index] ?? getChineseDictionaryEntry(hanzi).pinyin;
      const tone = getChineseToneNumber(pinyin);
      const toneStat = toneStats[tone] ?? toneStats[0];
      const missed = attempt.score < 82 && (transcriptUnits[index] !== hanzi || !transcriptUnits.includes(hanzi));
      toneStat.exposure += 1;
      toneStat.scoreTotal += attempt.score;
      if (missed) toneStat.misses += 1;

      const existing = hanziStats[hanzi] ?? {
        hanzi,
        pinyin,
        exposure: 0,
        misses: 0,
      };
      hanziStats[hanzi] = {
        ...existing,
        exposure: existing.exposure + 1,
        misses: existing.misses + (missed ? 1 : 0),
      };
    });
  });

  const toneWeaknesses = toneOrder.map<ChineseVoiceToneWeakness>((tone) => {
    const stat = toneStats[tone];
    const averageScore = stat.exposure ? Math.round(stat.scoreTotal / stat.exposure) : 100;
    const risk = stat.exposure ? Math.round((stat.misses / stat.exposure) * 100) : 0;
    const intensity = stat.exposure ? Math.max(risk, Math.round((100 - averageScore) * 0.72)) : 0;
    return {
      tone,
      name: stat.name,
      sample: stat.sample,
      exposure: stat.exposure,
      misses: stat.misses,
      risk,
      intensity,
      averageScore,
    };
  });

  const hanziHotspots = Object.values(hanziStats)
    .map<ChineseVoiceHanziHotspot>((item) => ({
      ...item,
      risk: item.exposure ? Math.round((item.misses / item.exposure) * 100) : 0,
    }))
    .filter((item) => item.misses > 0)
    .sort((a, b) => b.risk - a.risk || b.misses - a.misses || a.hanzi.localeCompare(b.hanzi))
    .slice(0, 8);

  return {
    attemptsAnalyzed: recentAttempts.length,
    toneWeaknesses,
    hanziHotspots,
  };
}

function getChineseMissedCharacterLedger({
  decoderResults,
  activePhraseUnits,
  activePinyinUnits,
  voiceHotspots,
  reviewItems,
}: {
  decoderResults: Array<{ target: string; typed: string; state: ChineseDecoderState }>;
  activePhraseUnits: string[];
  activePinyinUnits: string[];
  voiceHotspots: ChineseVoiceHanziHotspot[];
  reviewItems: Array<{
    card: { id: string; hanzi: string; pinyin: string };
    state: ChineseReviewState;
  }>;
}): ChineseMissedCharacterSignal[] {
  const grouped = new Map<
    string,
    {
      hanzi: string;
      pinyin: string;
      sources: Set<ChineseMissLedgerSource>;
      risk: number;
      count: number;
      detail: string[];
      action: string;
      reviewCardId?: string;
    }
  >();

  function addSignal({
    hanzi,
    pinyin,
    source,
    risk,
    count = 1,
    detail,
    action,
    reviewCardId,
  }: {
    hanzi: string;
    pinyin: string;
    source: ChineseMissLedgerSource;
    risk: number;
    count?: number;
    detail: string;
    action: string;
    reviewCardId?: string;
  }) {
    if (!hanzi) return;
    const existing = grouped.get(hanzi) ?? {
      hanzi,
      pinyin: pinyin || getChineseDictionaryEntry(hanzi).pinyin,
      sources: new Set<ChineseMissLedgerSource>(),
      risk: 0,
      count: 0,
      detail: [],
      action,
      reviewCardId,
    };
    existing.sources.add(source);
    existing.risk = Math.max(existing.risk, risk);
    existing.count += count;
    if (!existing.detail.includes(detail)) existing.detail.push(detail);
    if (!existing.reviewCardId && reviewCardId) existing.reviewCardId = reviewCardId;
    if (source === "srs") existing.action = "recall now";
    if (source === "voice" && existing.action !== "recall now") existing.action = "speak x5";
    grouped.set(hanzi, existing);
  }

  decoderResults.forEach((result, index) => {
    if (result.state === "pending" || result.state === "exact") return;
    const hanzi = activePhraseUnits[index];
    if (!hanzi) return;
    addSignal({
      hanzi,
      pinyin: activePinyinUnits[index] ?? result.target,
      source: "pinyin",
      risk: result.state === "miss" ? 82 : 56,
      detail: result.state === "miss" ? "pinyin mismatch" : "tone mismatch",
      action: "decode tone",
    });
  });

  voiceHotspots.forEach((hotspot) => {
    addSignal({
      hanzi: hotspot.hanzi,
      pinyin: hotspot.pinyin,
      source: "voice",
      risk: Math.max(44, hotspot.risk),
      count: hotspot.misses,
      detail: `${hotspot.misses}/${hotspot.exposure} voice`,
      action: "speak x5",
    });
  });

  reviewItems.forEach(({ card, state }) => {
    if (!state.lapses && state.rating !== "again") return;
    const units = getChineseSpeechUnits(card.hanzi);
    const pinyinUnits = getChinesePinyinUnits(card.pinyin);
    const retentionRisk = 100 - getChineseRetention(state);
    const risk = clampChinesePercent(42 + state.lapses * 18 + (state.rating === "again" ? 16 : 0) + retentionRisk * 0.22);
    units.forEach((hanzi, index) => {
      addSignal({
        hanzi,
        pinyin: pinyinUnits[index] ?? getChineseDictionaryEntry(hanzi).pinyin,
        source: "srs",
        risk,
        count: Math.max(1, state.lapses),
        detail: `${state.lapses || 1} SRS lapse`,
        action: "recall now",
        reviewCardId: card.id,
      });
    });
  });

  return Array.from(grouped.values())
    .map<ChineseMissedCharacterSignal>((item) => ({
      id: `${item.hanzi}-${Array.from(item.sources).sort().join("-")}`,
      hanzi: item.hanzi,
      pinyin: item.pinyin,
      sources: Array.from(item.sources).sort(),
      risk: clampChinesePercent(item.risk + Math.min(18, (item.sources.size - 1) * 8) + Math.min(12, item.count * 2)),
      count: item.count,
      detail: item.detail.slice(0, 2).join(" · "),
      action: item.action,
      reviewCardId: item.reviewCardId,
    }))
    .sort((a, b) => b.risk - a.risk || b.sources.length - a.sources.length || b.count - a.count || a.hanzi.localeCompare(b.hanzi))
    .slice(0, 6);
}

function getChineseAdaptiveRepairMission(
  heatmap: ReturnType<typeof getChineseVoiceHeatmap>,
  weaknesses: ChineseVoiceWeakness[],
  selectedDay: number,
): ChineseAdaptiveRepairMission {
  const targetDay = Math.min(selectedDay + 1, CHINESE_PRACTICE_TOTAL_DAYS);
  const fallbackTone = heatmap.toneWeaknesses[0];
  const tone = heatmap.toneWeaknesses.reduce(
    (winner, item) => (item.risk > winner.risk || (item.risk === winner.risk && item.misses > winner.misses) ? item : winner),
    fallbackTone,
  );
  const weaknessSymbols = weaknesses.map((weakness) => ({
    hanzi: weakness.hanzi,
    pinyin: weakness.pinyin,
    exposure: weakness.attempts,
    misses: weakness.attempts,
    risk: Math.max(0, 100 - weakness.averageScore),
  }));
  const symbols = [...heatmap.hanziHotspots, ...weaknessSymbols]
    .reduce<ChineseVoiceHanziHotspot[]>((unique, item) => {
      if (!unique.some((symbol) => symbol.hanzi === item.hanzi)) unique.push(item);
      return unique;
    }, [])
    .slice(0, 4);
  const hasSignal = heatmap.attemptsAnalyzed > 0 && (tone.misses > 0 || symbols.length > 0);
  const symbolText = symbols.length ? symbols.map((symbol) => symbol.hanzi).join(" ") : "active phrase";
  const key = [
    targetDay,
    `tone-${tone.tone}`,
    symbols.map((symbol) => symbol.hanzi).join("-") || "pending",
  ].join(":");
  const drillLabels = hasSignal
    ? [`T${tone.tone} shadow x8`, `${symbolText} recall x5`, "speak full sentence twice"]
    : ["capture speech", "score recall", "generate repair"];

  return {
    key,
    hasSignal,
    targetDay,
    tone,
    symbols,
    drills: drillLabels.map((label, index) => ({
      id: `${key}:drill-${index + 1}`,
      label,
      feedback: hasSignal
        ? index === 0
          ? "tone contour locked"
          : index === 1
            ? "symbol recall locked"
            : "spoken repair locked"
        : index === 0
          ? "voice capture needed"
          : index === 1
            ? "score needed"
            : "repair pending",
    })),
    command: hasSignal ? `load D${String(targetDay).padStart(3, "0")}` : "open focus tunnel",
    summary: hasSignal
      ? `${tone.name} tone · ${tone.risk}% risk · ${symbols.length || tone.misses} repair targets`
      : "voice attempts below 82% will generate tomorrow's repair injection",
  };
}

function getChineseRepairBaselineRisk(summary: string) {
  const match = summary.match(/(\d+)% risk/);
  return match ? Math.min(100, Math.max(0, Number(match[1]))) : 100;
}

function doesChineseAttemptMatchRepair(attempt: ChineseSpeechAttempt, entry: ChineseRepairHistoryEntry) {
  const phraseUnits = getChineseSpeechUnits(attempt.phrase);
  if (entry.symbols.some((symbol) => phraseUnits.includes(symbol))) return true;
  return getChinesePhrasePinyinForSpeech(attempt.phrase).some((token) => getChineseToneNumber(token) === entry.tone);
}

function getChineseRepairComparison(
  history: ChineseRepairHistoryEntry[],
  attempts: ChineseSpeechAttempt[],
): ChineseRepairComparison {
  const entry = history[0];
  if (!entry) {
    return {
      status: "empty",
      label: "no repair baseline",
      detail: "lock a repair mission to compare the next spoken attempt",
      baselineRisk: 0,
      followUpRisk: null,
      delta: 0,
    };
  }

  const completedAt = Date.parse(entry.completedAt);
  const baselineRisk = getChineseRepairBaselineRisk(entry.summary);
  const followUp = attempts
    .filter((attempt) => Date.parse(attempt.createdAt) > completedAt && doesChineseAttemptMatchRepair(attempt, entry))
    .sort((a, b) => Date.parse(a.createdAt) - Date.parse(b.createdAt))[0];

  if (!followUp) {
    return {
      status: "waiting",
      label: "awaiting voice check",
      detail: `speak T${entry.tone} ${entry.symbols.join(" ") || entry.toneName} after repair`,
      baselineRisk,
      followUpRisk: null,
      delta: 0,
      entry,
    };
  }

  const followUpRisk = Math.max(0, 100 - followUp.score);
  const delta = baselineRisk - followUpRisk;
  const status = delta > 0 ? "improved" : "hot";

  return {
    status,
    label: status === "improved" ? "risk dropped" : "risk still hot",
    detail: `${followUp.score}% voice score · ${followUp.matched}/${followUp.total} hanzi matched`,
    baselineRisk,
    followUpRisk,
    delta,
    attempt: followUp,
    entry,
  };
}

function clampChinesePercent(value: number) {
  return Math.min(100, Math.max(0, Math.round(Number.isFinite(value) ? value : 0)));
}

function getChinesePlacementBand(knownCharacters: number) {
  return (
    chineseHskPlacementBands.find((band) => knownCharacters <= band.ceiling) ??
    chineseHskPlacementBands[chineseHskPlacementBands.length - 1]
  );
}

function getChinesePlacementProfile({
  knownCharacters,
  reviewMastery,
  accuracy,
  reviewedCount,
  activeSpeechAverage,
  speechAttemptCount,
  decoderScore,
  hasDecoderInput,
  assemblyProgress,
  assemblyTileCount,
  strokeProgress,
  strokeCompletedCount,
  selectedPracticeDay,
}: {
  knownCharacters: number;
  reviewMastery: number;
  accuracy: number;
  reviewedCount: number;
  activeSpeechAverage: number;
  speechAttemptCount: number;
  decoderScore: number;
  hasDecoderInput: boolean;
  assemblyProgress: number;
  assemblyTileCount: number;
  strokeProgress: number;
  strokeCompletedCount: number;
  selectedPracticeDay: number;
}): ChinesePlacementProfile {
  const band = getChinesePlacementBand(knownCharacters);
  const bandSpan = Math.max(1, band.ceiling - band.floor);
  const bandProgress = clampChinesePercent(((knownCharacters - band.floor) / bandSpan) * 100);
  const signals: ChinesePlacementSignal[] = [
    {
      id: "retention",
      label: "retention",
      score: reviewedCount ? clampChinesePercent(reviewMastery) : 50,
      detail: reviewedCount ? `${reviewedCount} reviews` : "needs reviews",
      active: reviewedCount > 0,
    },
    {
      id: "accuracy",
      label: "accuracy",
      score: reviewedCount ? clampChinesePercent(accuracy) : 50,
      detail: reviewedCount ? "good/easy ratio" : "needs grades",
      active: reviewedCount > 0,
    },
    {
      id: "tone",
      label: "tone",
      score: speechAttemptCount ? clampChinesePercent(activeSpeechAverage) : 50,
      detail: speechAttemptCount ? `${speechAttemptCount} voice traces` : "needs speech",
      active: speechAttemptCount > 0,
    },
    {
      id: "pinyin",
      label: "pinyin",
      score: hasDecoderInput ? clampChinesePercent(decoderScore) : 50,
      detail: hasDecoderInput ? "decoder sample" : "needs input",
      active: hasDecoderInput,
    },
    {
      id: "syntax",
      label: "syntax",
      score: assemblyTileCount ? clampChinesePercent(assemblyProgress) : 50,
      detail: assemblyTileCount ? `${assemblyTileCount} slots` : "needs assembly",
      active: assemblyTileCount > 0,
    },
    {
      id: "stroke",
      label: "stroke",
      score: strokeCompletedCount ? clampChinesePercent(strokeProgress) : 50,
      detail: strokeCompletedCount ? `${strokeCompletedCount}/4 passes` : "needs trace",
      active: strokeCompletedCount > 0,
    },
  ];
  const evidenceCount = signals.filter((signal) => signal.active).length;
  const readiness = clampChinesePercent(
    signals.reduce((total, signal) => total + signal.score, 0) / Math.max(signals.length, 1),
  );
  const confidence = clampChinesePercent((evidenceCount / signals.length) * 100);
  const rawDay =
    band.startDay + Math.round(((band.endDay - band.startDay) * bandProgress) / 100) + (readiness >= 78 ? 10 : readiness < 48 ? -10 : 0);
  const boundedDay =
    evidenceCount < 3
      ? selectedPracticeDay
      : Math.min(
          Math.max(rawDay, Math.max(1, selectedPracticeDay - 30)),
          Math.min(CHINESE_PRACTICE_TOTAL_DAYS, selectedPracticeDay + 30),
        );
  const recommendedDay = Math.min(Math.max(Math.round(boundedDay), 1), CHINESE_PRACTICE_TOTAL_DAYS);
  const deltaDays = recommendedDay - selectedPracticeDay;
  const status =
    confidence < 50
      ? "sample"
      : readiness < 55
        ? "repair"
        : deltaDays > 3
          ? "advance"
          : "steady";

  return {
    status,
    hskLabel: `${band.label} · ${bandProgress}% band`,
    readiness,
    confidence,
    recommendedDay,
    recommendedWords: getChinesePracticeDay(recommendedDay).wordsPerDay,
    deltaDays,
    summary:
      status === "sample"
        ? "run one listen-build-write-recall sample before moving the schedule"
        : status === "repair"
          ? "hold placement and repair weak recall before increasing load"
          : status === "advance"
            ? `advance ${deltaDays} days with current evidence`
            : "placement and daily load are aligned",
    action: status === "sample" ? "run sample" : deltaDays === 0 ? "hold day" : `apply D${String(recommendedDay).padStart(3, "0")}`,
    signals,
  };
}

function getChinesePlacementWindowStats(startDay: number, dayCount = 7): ChinesePlacementOutcomeWindow {
  const start = Math.min(Math.max(Math.trunc(startDay), 1), CHINESE_PRACTICE_TOTAL_DAYS);
  const end = Math.min(Math.max(start + dayCount - 1, start), CHINESE_PRACTICE_TOTAL_DAYS);
  const days = Array.from({ length: end - start + 1 }, (_, index) => getChinesePracticeDay(start + index));
  const newWords = days.reduce((total, day) => total + day.wordsPerDay, 0);
  const reviewWords = days.reduce(
    (total, day) =>
      total + day.reviewAnchors.reduce((anchorTotal, anchor) => anchorTotal + getChinesePracticeDay(anchor.day).wordsPerDay, 0),
    0,
  );
  const totalLoad = newWords + reviewWords;

  return {
    startDay: start,
    endDay: end,
    days: days.length,
    newWords,
    reviewWords,
    totalLoad,
    averageLoad: Math.round(totalLoad / Math.max(days.length, 1)),
  };
}

function getChinesePlacementOutcome(history: ChinesePlacementHistoryEntry[]): ChinesePlacementOutcome {
  const entry = history[0];
  const emptyWindow = getChinesePlacementWindowStats(CHINESE_TODAY_INDEX, 1);
  if (!entry) {
    return {
      status: "empty",
      label: "no outcome baseline",
      detail: "run a placement calibration to compare weekly load",
      before: emptyWindow,
      after: emptyWindow,
      deltaAverage: 0,
      deltaNewWords: 0,
      deltaReviewWords: 0,
    };
  }

  const before = getChinesePlacementWindowStats(Math.max(1, entry.fromDay - 7), 7);
  const after = getChinesePlacementWindowStats(entry.toDay, 7);
  const deltaAverage = after.averageLoad - before.averageLoad;
  const deltaNewWords = after.newWords - before.newWords;
  const deltaReviewWords = after.reviewWords - before.reviewWords;
  const status = deltaAverage >= 8 ? "heavier" : deltaAverage <= -8 ? "lighter" : "steady";
  const label =
    status === "heavier"
      ? "load increased"
      : status === "lighter"
        ? "load eased"
        : entry.status === "sample"
          ? "sample captured"
          : "load stable";
  const detail =
    status === "heavier" && entry.readiness < 60
      ? "watch overload before advancing again"
      : status === "heavier"
        ? "advance is bounded by current readiness"
        : status === "lighter"
          ? "repair window creates recovery space"
          : "weekly pressure stayed aligned";

  return {
    status,
    label,
    detail,
    before,
    after,
    deltaAverage,
    deltaNewWords,
    deltaReviewWords,
    entry,
  };
}

function getChinesePracticeAnchorLoad(day: number) {
  return getChinesePracticeDay(day).reviewAnchors.reduce(
    (total, anchor) => total + getChinesePracticeDay(anchor.day).wordsPerDay,
    0,
  );
}

function getChineseLoadStatus(pressure: number): ChineseLoadForecastStatus {
  if (pressure >= 92) return "overload";
  if (pressure >= 72) return "heavy";
  if (pressure <= 38) return "light";
  return "steady";
}

function getChineseLoadForecast({
  startDay,
  reviewStates,
  repairTargetDay,
  repairActive,
}: {
  startDay: number;
  reviewStates: ChineseReviewState[];
  repairTargetDay: number;
  repairActive: boolean;
}): ChineseLoadForecast {
  const safeStart = Math.min(Math.max(Math.trunc(startDay), 1), CHINESE_PRACTICE_TOTAL_DAYS);
  const days = Array.from({ length: 7 }, (_, index): ChineseLoadForecastDay => {
    const day = Math.min(safeStart + index, CHINESE_PRACTICE_TOTAL_DAYS);
    const record = getChinesePracticeDay(day);
    const anchorReviewWords = getChinesePracticeAnchorLoad(day);
    const srsDue = reviewStates.filter((state) => ["NEW", "DUE", "LATE"].includes(getChineseReviewStatus(state, day))).length;
    const soonDue = reviewStates.filter((state) => getChineseReviewStatus(state, day) === "SOON").length;
    const repairLoad = repairActive && repairTargetDay === day ? 12 : 0;
    const totalLoad = Math.round(record.wordsPerDay + anchorReviewWords + srsDue + soonDue * 0.5 + repairLoad);
    const expectedLoad = Math.max(55, record.wordsPerDay + anchorReviewWords + 20);
    const pressure = clampChinesePercent((totalLoad / expectedLoad) * 100);
    const status = getChineseLoadStatus(pressure);
    const recommendation =
      status === "overload"
        ? "review only"
        : status === "heavy"
          ? "preload srs"
          : status === "light"
            ? "advance ok"
            : "normal loop";

    return {
      day,
      label: index === 0 ? "today" : `D+${index}`,
      newWords: record.wordsPerDay,
      anchorReviewWords,
      srsDue,
      soonDue,
      repairLoad,
      totalLoad,
      pressure,
      status,
      recommendation,
    };
  });
  const peak = days.reduce((highest, day) => (day.totalLoad > highest.totalLoad ? day : highest), days[0]);
  const recommended = days.reduce((lightest, day) => (day.pressure < lightest.pressure ? day : lightest), days[0]);
  const averageLoad = Math.round(days.reduce((total, day) => total + day.totalLoad, 0) / Math.max(days.length, 1));
  const trend = days[days.length - 1].totalLoad - days[0].totalLoad;
  const status = getChineseLoadStatus(Math.max(peak.pressure, Math.round(averageLoad / Math.max(peak.totalLoad, 1) * peak.pressure)));
  const label =
    status === "overload"
      ? "overload forming"
      : status === "heavy"
        ? "pressure rising"
        : status === "light"
          ? "recovery window"
          : "load stable";
  const action =
    status === "overload"
      ? `load D${String(recommended.day).padStart(3, "0")}`
      : status === "heavy"
        ? "preload reviews"
        : status === "light"
          ? "advance gently"
          : "hold rhythm";

  return {
    status,
    label,
    summary:
      status === "overload"
        ? `Peak D${String(peak.day).padStart(3, "0")} needs a lighter lane.`
        : status === "heavy"
          ? `Peak D${String(peak.day).padStart(3, "0")} is review-heavy; drain SRS early.`
          : status === "light"
            ? `D${String(recommended.day).padStart(3, "0")} has room for careful advance.`
            : "The next seven days can stay on the guided loop.",
    action,
    averageLoad,
    peak,
    recommendedDay: recommended.day,
    trend,
    days,
  };
}

function getChineseEvidenceChecksum(value: string) {
  let hash = 0;
  for (let index = 0; index < value.length; index += 1) {
    hash = (hash * 31 + value.charCodeAt(index)) >>> 0;
  }
  return hash.toString(36).toUpperCase().padStart(7, "0").slice(-7);
}

function getChineseCoachBriefing(packet: ChineseCoachEvidencePacket): ChineseCoachBriefing {
  const weakSymbols = packet.voice.weakHanzi.length ? packet.voice.weakHanzi.slice(0, 3).join(" ") : packet.scope.activeWord;

  if ((packet.forecast.status === "overload" || packet.forecast.status === "heavy") && packet.forecast.shield !== "unlocked") {
    if (packet.forecast.shield === "ready") {
      return {
        mode: "forecast",
        signal: "gate clear",
        title: "Resume new words",
        body: `${packet.forecast.unlockProgress}/${packet.forecast.unlockTarget} review cards cleared the pressure gate.`,
        why: "The review-first lock has enough evidence to restore the daily rail.",
        steps: ["Restore new-word rail", "Load the active word", "Keep recall warm after the lesson"],
        command: "unlock words",
        urgency: 34,
      };
    }

    return {
      mode: "forecast",
      signal: "load forecast",
      title: packet.forecast.status === "overload" ? "Protect the next week" : "Review before new words",
      body: `D${String(packet.forecast.peakDay).padStart(3, "0")} is forecast at ${packet.forecast.peakLoad} load units.`,
      why: packet.forecast.recommendation,
      steps: ["Shield new words", "Drain due SRS", "Return when pressure stabilizes"],
      command: "review first",
      urgency: Math.min(100, packet.forecast.peakLoad + (packet.forecast.status === "overload" ? 12 : 0)),
    };
  }

  if (packet.placement.status === "sample" || packet.placement.confidence < 50) {
    return {
      mode: "sample",
      signal: "calibrate",
      title: "Run one clean sample",
      body: `Hold D${String(packet.scope.day).padStart(3, "0")} until listen, build, write, and recall all produce evidence.`,
      why: `${packet.placement.confidence}% placement confidence is too thin for a schedule move.`,
      steps: ["Open Focus Tunnel", `Shadow ${packet.scope.activeWord}`, "Build, write, then grade recall"],
      command: "run sample",
      urgency: 100 - packet.placement.confidence,
    };
  }

  if (packet.repair.delta <= 0 && (packet.voice.weakHanzi.length > 0 || packet.voice.average < 70)) {
    return {
      mode: "repair",
      signal: "tone repair",
      title: "Repair spoken drift",
      body: `Prioritize ${weakSymbols} before adding new load.`,
      why: `${packet.voice.weakTone} is still the highest-risk voice signal.`,
      steps: [`Replay ${packet.voice.weakTone}`, `Speak ${weakSymbols} five times`, "Lock the repair mission"],
      command: "load repair",
      urgency: Math.min(100, 100 - packet.voice.average + 20),
    };
  }

  if (packet.srs.due >= 10) {
    return {
      mode: "review",
      signal: "memory pressure",
      title: "Drain the due queue",
      body: `${packet.srs.due} cards are due; clear memory pressure before chasing new words.`,
      why: `${packet.srs.retention}% retained with ${packet.srs.accuracy}% accuracy.`,
      steps: ["Grade due cards first", "Mark weak ones hard", "Return to today’s active word"],
      command: "open queue",
      urgency: Math.min(100, packet.srs.due * 5),
    };
  }

  if (packet.placement.weeklyDelta > 8 && packet.placement.readiness < 65) {
    return {
      mode: "placement",
      signal: "load guard",
      title: "Hold the load",
      body: "The next week got heavier before readiness caught up.",
      why: `${packet.placement.weeklyDelta} average-load delta at ${packet.placement.readiness}% readiness.`,
      steps: ["Stay on current day", "Finish daily circuit", "Recheck placement after recall"],
      command: "hold day",
      urgency: Math.min(100, packet.placement.weeklyDelta + (65 - packet.placement.readiness)),
    };
  }

  if (packet.voice.average > 0 && packet.voice.average < 82) {
    return {
      mode: "voice",
      signal: "voice polish",
      title: "Sharpen pronunciation",
      body: `Voice average is ${packet.voice.average}%; add one spoken pass before SRS grading.`,
      why: `${packet.voice.weakTone} needs another clean output sample.`,
      steps: ["Play audio", "Speak full sentence", "Grade only after clean output"],
      command: "voice pass",
      urgency: 82 - packet.voice.average,
    };
  }

  return {
    mode: "flow",
    signal: "green path",
    title: "Continue the circuit",
    body: packet.nextAction,
    why: `${packet.placement.outcome}; ${packet.srs.due} cards due.`,
    steps: ["Run guided command", "Load active word", "Keep combo alive"],
    command: "continue",
    urgency: Math.max(10, Math.min(100, packet.srs.due * 3 + Math.abs(packet.placement.weeklyDelta))),
  };
}

function getChineseCoachHistoryBaseline(packet: ChineseCoachEvidencePacket): ChineseCoachHistoryBaseline {
  return {
    reviewed: packet.srs.reviewed,
    due: packet.srs.due,
    accuracy: packet.srs.accuracy,
    retention: packet.srs.retention,
    voiceAverage: packet.voice.average,
    repairDelta: packet.repair.delta,
    placementReadiness: packet.placement.readiness,
    placementConfidence: packet.placement.confidence,
    placementWeeklyDelta: packet.placement.weeklyDelta,
    forecastPeakLoad: packet.forecast.peakLoad,
    forecastAverageLoad: packet.forecast.averageLoad,
    xp: packet.memory.xp,
    combo: packet.memory.combo,
  };
}

function getSignedChineseDelta(value: number, suffix = "") {
  const rounded = Math.round(value);
  return `${rounded > 0 ? "+" : ""}${rounded}${suffix}`;
}

function getChineseCoachHistoryOutcome(
  entry: ChineseCoachHistoryEntry,
  packet: ChineseCoachEvidencePacket,
): ChineseCoachHistoryOutcome {
  const current = getChineseCoachHistoryBaseline(packet);
  const reviewedDelta = current.reviewed - entry.baseline.reviewed;
  const dueReduced = entry.baseline.due - current.due;
  const retentionDelta = current.retention - entry.baseline.retention;
  const accuracyDelta = current.accuracy - entry.baseline.accuracy;
  const voiceDelta = current.voiceAverage - entry.baseline.voiceAverage;
  const repairDelta = current.repairDelta - entry.baseline.repairDelta;
  const placementRiskDelta = Math.abs(entry.baseline.placementWeeklyDelta) - Math.abs(current.placementWeeklyDelta);
  const readinessDelta = current.placementReadiness - entry.baseline.placementReadiness;
  const confidenceDelta = current.placementConfidence - entry.baseline.placementConfidence;
  const forecastPeakDelta = entry.baseline.forecastPeakLoad - current.forecastPeakLoad;
  const forecastAverageDelta = entry.baseline.forecastAverageLoad - current.forecastAverageLoad;
  const comboDelta = current.combo - entry.baseline.combo;
  const hasMovement =
    reviewedDelta !== 0 ||
    dueReduced !== 0 ||
    retentionDelta !== 0 ||
    accuracyDelta !== 0 ||
    voiceDelta !== 0 ||
    repairDelta !== 0 ||
    placementRiskDelta !== 0 ||
    readinessDelta !== 0 ||
    confidenceDelta !== 0 ||
    forecastPeakDelta !== 0 ||
    forecastAverageDelta !== 0 ||
    comboDelta !== 0;

  if (!hasMovement) {
    return {
      status: "waiting",
      label: "awaiting evidence",
      detail: "run the command, then review, speak, or calibrate to measure impact",
      delta: "0 signal",
      weight: 12,
    };
  }

  if (entry.mode === "review") {
    const score = dueReduced * 3 + retentionDelta + accuracyDelta + reviewedDelta;
    const improved = dueReduced > 0 || retentionDelta > 1 || accuracyDelta > 1;
    const hot = dueReduced < 0 && retentionDelta < 0;
    return {
      status: improved ? "improved" : hot ? "hot" : "steady",
      label: improved ? "queue eased" : hot ? "memory pressure" : "review stable",
      detail: `${getSignedChineseDelta(-dueReduced)} due · ${getSignedChineseDelta(retentionDelta, "%")} retention`,
      delta: `${getSignedChineseDelta(score)} srs`,
      weight: clampChinesePercent(50 + score),
    };
  }

  if (entry.mode === "voice" || entry.mode === "sample") {
    const score = voiceDelta + confidenceDelta + reviewedDelta;
    const improved = voiceDelta > 0 || confidenceDelta > 0;
    const hot = voiceDelta < 0 && confidenceDelta <= 0;
    return {
      status: improved ? "improved" : hot ? "hot" : "steady",
      label: improved ? "speech signal up" : hot ? "speech still thin" : "sample stable",
      detail: `${getSignedChineseDelta(voiceDelta, "%")} voice · ${getSignedChineseDelta(confidenceDelta, "%")} conf`,
      delta: `${getSignedChineseDelta(score)} voice`,
      weight: clampChinesePercent(50 + score),
    };
  }

  if (entry.mode === "repair") {
    const score = repairDelta * 2 + voiceDelta + comboDelta;
    const improved = repairDelta > 0 || voiceDelta > 0 || comboDelta > 0;
    const hot = repairDelta < 0 && voiceDelta <= 0;
    return {
      status: improved ? "improved" : hot ? "hot" : "steady",
      label: improved ? "repair taking hold" : hot ? "repair still hot" : "repair stable",
      detail: `${getSignedChineseDelta(repairDelta, "%")} risk · ${getSignedChineseDelta(voiceDelta, "%")} voice`,
      delta: `${getSignedChineseDelta(score)} repair`,
      weight: clampChinesePercent(50 + score),
    };
  }

  if (entry.mode === "placement") {
    const score = placementRiskDelta + readinessDelta + confidenceDelta;
    const improved = placementRiskDelta > 0 || readinessDelta > 0;
    const hot = placementRiskDelta < 0 && readinessDelta < 0;
    return {
      status: improved ? "improved" : hot ? "hot" : "steady",
      label: improved ? "load aligned" : hot ? "load drift" : "placement stable",
      detail: `${getSignedChineseDelta(placementRiskDelta)} load risk · ${getSignedChineseDelta(readinessDelta, "%")} ready`,
      delta: `${getSignedChineseDelta(score)} place`,
      weight: clampChinesePercent(50 + score),
    };
  }

  if (entry.mode === "forecast") {
    const score = forecastPeakDelta * 2 + forecastAverageDelta + dueReduced;
    const improved = forecastPeakDelta > 0 || forecastAverageDelta > 0 || dueReduced > 0;
    const hot = forecastPeakDelta < 0 && forecastAverageDelta < 0;
    return {
      status: improved ? "improved" : hot ? "hot" : "steady",
      label: improved ? "load cooled" : hot ? "load still rising" : "forecast steady",
      detail: `${getSignedChineseDelta(forecastPeakDelta)} peak · ${getSignedChineseDelta(forecastAverageDelta)} avg`,
      delta: `${getSignedChineseDelta(score)} load`,
      weight: clampChinesePercent(50 + score),
    };
  }

  const score = reviewedDelta + dueReduced * 2 + retentionDelta + voiceDelta + comboDelta;
  const improved = score > 2;
  const hot = score < -2;
  return {
    status: improved ? "improved" : hot ? "hot" : "steady",
    label: improved ? "circuit gained" : hot ? "circuit drag" : "circuit stable",
    detail: `${getSignedChineseDelta(reviewedDelta)} reviews · ${getSignedChineseDelta(comboDelta)} combo`,
    delta: `${getSignedChineseDelta(score)} flow`,
    weight: clampChinesePercent(50 + score),
  };
}

function getChineseHskProgress(level: (typeof chineseHskLevels)[number], masteredCharacters: number) {
  const boostedKnown = level.name === "HSK 3" ? Math.min(level.total, level.known + masteredCharacters) : level.known;
  return {
    known: boostedKnown,
    progress: Math.round((boostedKnown / level.total) * 100),
  };
}

function normalizeChinesePinyinToken(token: string) {
  const lowered = token.trim().toLowerCase().replace(/[.,?。？！]/g, "");
  const numberedTone = lowered.match(/[1-5]$/)?.[0];
  let tone = numberedTone ? Number(numberedTone) : 0;
  const withoutNumber = numberedTone ? lowered.slice(0, -1) : lowered;
  let base = "";
  for (const character of withoutNumber) {
    const mapped = chinesePinyinToneMap[character];
    if (mapped) {
      base += mapped.base;
      if (mapped.tone) tone = mapped.tone;
    } else if (/[a-z]/.test(character)) {
      base += character;
    }
  }
  return {
    base,
    tone: tone === 5 ? 0 : tone,
    exact: `${base}:${tone === 5 ? 0 : tone}`,
  };
}

