  useEffect(() => {
    if (!lessonFocusActive) return;
    function closeFocusOnEscape(event: KeyboardEvent) {
      const target = event.target as HTMLElement | null;
      if (target?.closest("input, textarea, select") || target?.isContentEditable) return;

      if (event.key === "Escape") {
        event.preventDefault();
        setLessonFocusActive(false);
        return;
      }

      if (event.key === "Enter") {
        event.preventDefault();
        runGuidedCircuitStep(activeLessonStep);
        return;
      }

      if (event.key === " " || event.code === "Space") {
        event.preventDefault();
        speakMandarin(activePhrase.hanzi);
        return;
      }

      if (event.key.toLowerCase() === "v") {
        event.preventDefault();
        startSpeechGate();
        return;
      }

      const stepIndex = Number(event.key) - 1;
      if (stepIndex >= 0 && stepIndex < chineseLessonSteps.length) {
        event.preventDefault();
        setActiveLessonStep(chineseLessonSteps[stepIndex].id);
      }
    }
    window.addEventListener("keydown", closeFocusOnEscape);
    return () => window.removeEventListener("keydown", closeFocusOnEscape);
  }, [
    activeDictionaryEntry.hanzi,
    activeLessonStep,
    activePhrase.hanzi,
    activePhraseReviewId,
    activeStrokePrefix,
    assemblyAttemptUnits.length,
    assemblyTileIds,
    lessonFocusActive,
    nextCircuitStep.id,
    speechStatus,
    strokeMatrixDone,
  ]);

  function selectLesson(id: string) {
    setActiveLessonId(id);
    setSelectedCharacterIndex(0);
    setSelectedPhraseIndex(0);
    setPinyinDecoderInput("");
    setSelectedOption("");
    setActiveLessonStep("listen");
    setDictionaryToken((chineseLessons.find((lesson) => lesson.id === id) ?? chineseLessons[0]).characters[0].hanzi);
    setRewardMessage("");
  }

  function toggleDrill(id: string) {
    setCompletedDrills((current) => {
      const next = new Set(current);
      if (next.has(id)) {
        next.delete(id);
      } else {
        next.add(id);
      }
      return next;
    });
  }

  function selectAssemblyTile(id: string) {
    setAssemblyTileIds((current) => (current.includes(id) ? current : [...current, id]));
  }

  function removeAssemblyTile(id: string) {
    setAssemblyTileIds((current) => current.filter((tileId) => tileId !== id));
  }

  function openDictionary(token: string) {
    const rawToken = token.trim();
    const cleanToken =
      chineseDictionary[rawToken] || chinesePracticeWordIndex[rawToken]
        ? rawToken
        : getChinesePhraseUnits(token)[0] ?? rawToken;
    if (!cleanToken) return;
    setDictionaryToken(cleanToken);
  }

  function selectPracticeDay(day: number) {
    setSelectedPracticeDay(Math.min(Math.max(Math.trunc(day), 1), CHINESE_PRACTICE_TOTAL_DAYS));
  }

  function loadPracticeWord(word: { hanzi: string; pinyin: string; practiceId: string }) {
    openDictionary(word.hanzi);
    setCardRevealed(true);
    setActiveLessonStep("meaning");
    setRewardMessage(`${word.practiceId} loaded · ${word.pinyin}`);
  }

  function loadAdaptiveRepairMission() {
    if (!adaptiveRepairMission.hasSignal) {
      setLessonFocusActive(true);
      setRewardMessage("repair uplink waiting · capture voice first");
      return;
    }

    selectPracticeDay(adaptiveRepairMission.targetDay);
    const primarySymbol = adaptiveRepairMission.symbols[0];
    if (primarySymbol) openDictionary(primarySymbol.hanzi);
    setActiveLessonStep("listen");
    setCardRevealed(Boolean(primarySymbol));
    setRewardMessage(
      `D${String(adaptiveRepairMission.targetDay).padStart(3, "0")} repair queued · T${adaptiveRepairMission.tone.tone}`,
    );
  }

  function openRepairHistoryEntry(entry: ChineseRepairHistoryEntry) {
    selectPracticeDay(entry.day);
    const primarySymbol = entry.symbols[0];
    if (primarySymbol) openDictionary(primarySymbol);
    setRewardMessage(`repair history loaded · T${entry.tone} ${entry.toneName}`);
  }

  function openReviewUnlockEntry(entry: ChineseReviewUnlockEntry) {
    selectPracticeDay(entry.day);
    setRewardMessage(`review gate loaded · ${entry.status} · ${entry.reviewedCards}/${entry.target}`);
  }

  function getMissDrillReviewCard(signal: ChineseMissedCharacterSignal) {
    return (
      (signal.reviewCardId ? reviewCards.find((card) => card.id === signal.reviewCardId) : undefined) ??
      reviewCards.find((card) => getChineseCardCharacters(card).includes(signal.hanzi))
    );
  }

  function stageMissDrillSignal(signal: ChineseMissedCharacterSignal, openFocus = false) {
    const card = getMissDrillReviewCard(signal);
    setActiveMissDrillSnapshot(signal);
    openDictionary(signal.hanzi);
    setCardRevealed(true);

    if (card) {
      setActiveLessonId(card.lessonId);
      setSelectedPhraseIndex(card.exampleIndex);
      setActiveReviewId(card.id);
      if (openFocus) setLessonFocusActive(true);
    }

    return card;
  }

  function loadMissedCharacterSignal(signal: ChineseMissedCharacterSignal) {
    const card = stageMissDrillSignal(signal, signal.sources.includes("srs"));
    if (signal.reviewCardId && card) {
      loadReviewFirstCard(card, signal.sources.includes("srs"));
    } else if (signal.sources.includes("voice")) {
      setLessonFocusActive(true);
      setActiveLessonStep("recall");
    } else {
      setActiveLessonStep("build");
      setPinyinDecoderInput("");
    }
    setRewardMessage(`miss ledger loaded · ${signal.hanzi} · ${signal.sources.join("+")}`);
  }

  function resetMissDrillProgress(signalId: string) {
    setMissDrillDone((current) => {
      const next = new Set(current);
      chineseMissDrillSteps.forEach((step) => next.delete(`${signalId}:${step.id}`));
      return next;
    });
  }

  function armMissDrill(
    signal = topMissedCharacter,
    options: { reset?: boolean; followUpId?: string } = {},
  ) {
    if (!signal) {
      setRewardMessage("miss drill waiting · create a pinyin, voice, or SRS miss first");
      return;
    }

    if (options.reset) resetMissDrillProgress(signal.id);
    setActiveMissFollowUpId(options.followUpId ?? "");
    stageMissDrillSignal(signal);
    setActiveLessonStep("build");
    setPinyinDecoderInput("");
    setRewardMessage(`micro drill armed · ${signal.hanzi} · ${signal.sources.join("+")}`);
  }

  function repeatMissDrillEntry(entry: ChineseMissDrillHistoryEntry) {
    armMissDrill(
      {
        id: entry.signalId,
        hanzi: entry.hanzi,
        pinyin: entry.pinyin,
        sources: entry.sources,
        risk: entry.risk,
        count: 1,
        detail: `${entry.score}% packet`,
        action: "repeat micro drill",
      },
      { reset: true },
    );
  }

  function scheduleMissFollowUp(signal: ChineseMissedCharacterSignal, completedDay: number) {
    setMissDrillFollowUps((current) => {
      const existing = current.find((entry) => entry.signalId === signal.id);
      const isActiveFollowUp = Boolean(activeMissFollowUpId && existing?.id === activeMissFollowUpId);
      const currentSignal = missedCharacterLedger.find((entry) => entry.id === signal.id);
      const outcome = existing && isActiveFollowUp ? getChineseMissFollowUpOutcome(existing, currentSignal) : null;
      const attempts = isActiveFollowUp ? (existing?.attempts ?? 0) + 1 : existing?.attempts ?? 0;
      const nextSignal = outcome
        ? {
            risk: outcome.afterRisk,
            sources: outcome.afterSources,
          }
        : signal;
      const interval = getChineseMissFollowUpInterval(nextSignal, attempts);
      const outcomePoint =
        outcome && isChineseMissFollowUpResolvedStatus(outcome.status)
          ? {
              id: `${signal.id}-trend-${completedDay}-${attempts}`,
              day: completedDay,
              status: outcome.status,
              delta: Math.round(outcome.delta),
              risk: outcome.afterRisk,
              sources: outcome.afterSources,
            }
          : null;
      const outcomeHistory = outcomePoint
        ? [outcomePoint, ...(existing?.outcomeHistory ?? [])].slice(0, CHINESE_MISS_FOLLOW_UP_TREND_LIMIT)
        : (existing?.outcomeHistory ?? []);
      const nextEntry: ChineseMissDrillFollowUpEntry = {
        id: existing?.id ?? `${signal.id}-follow-up`,
        signalId: signal.id,
        hanzi: signal.hanzi,
        pinyin: signal.pinyin,
        sources: signal.sources,
        risk: outcome ? outcome.afterRisk : signal.risk,
        baselineRisk: existing?.baselineRisk ?? signal.risk,
        createdDay: existing?.createdDay ?? completedDay,
        dueDay: Math.min(CHINESE_PRACTICE_TOTAL_DAYS, completedDay + interval),
        interval,
        attempts,
        lastCompletedDay: completedDay,
        lastOutcome: outcome?.status ?? "waiting",
        lastDelta: outcome?.delta ?? 0,
        lastSignalRisk: outcome?.afterRisk ?? signal.risk,
        lastSources: outcome?.afterSources ?? signal.sources,
        outcomeHistory,
      };

      return [nextEntry, ...current.filter((entry) => entry.id !== nextEntry.id)]
        .sort((a, b) => a.dueDay - b.dueDay || b.risk - a.risk)
        .slice(0, CHINESE_MISS_FOLLOW_UP_LIMIT);
    });
  }

  function loadMissFollowUp(entry: ChineseMissDrillFollowUpEntry) {
    const signal = getChineseMissFollowUpSignal(entry);
    armMissDrill(signal, { reset: true, followUpId: entry.id });
    setRewardMessage(
      `${getChineseMissFollowUpDueLabel(entry, selectedPracticeRecord.day)} · ${entry.hanzi} follow-up armed`,
    );
  }

  function runMissDrillStep(stepId: ChineseMissDrillStepId) {
    const signal = activeMissDrillSignal ?? topMissedCharacter;
    if (!signal) {
      setRewardMessage("micro drill waiting · no miss signal");
      return;
    }

    const card = stageMissDrillSignal(signal);
    const doneKey = `${signal.id}:${stepId}`;
    if (missDrillDone.has(doneKey)) {
      const lockedCount = chineseMissDrillSteps.filter((step) => missDrillDone.has(`${signal.id}:${step.id}`)).length;
      setRewardMessage(`${signal.hanzi} ${stepId} already locked · ${lockedCount}/${chineseMissDrillSteps.length}`);
      return;
    }

    const nextDone = new Set(missDrillDone).add(doneKey);
    setMissDrillDone(nextDone);

    if (stepId === "decode") {
      setActiveLessonStep("build");
      setPinyinDecoderInput(signal.pinyin);
    }

    if (stepId === "speak") {
      setActiveLessonStep("recall");
    }

    if (stepId === "write") {
      setActiveLessonStep("write");
      openDictionary(signal.hanzi);
    }

    if (stepId === "recall") {
      setActiveLessonStep("recall");
      if (card) setActiveReviewId(card.id);
    }

    const nextDoneCount = chineseMissDrillSteps.filter((step) => nextDone.has(`${signal.id}:${step.id}`)).length;
    const allDone = nextDoneCount === chineseMissDrillSteps.length;
    if (allDone) {
      const entry: ChineseMissDrillHistoryEntry = {
        id: `${signal.id}:${Date.now()}`,
        signalId: signal.id,
        hanzi: signal.hanzi,
        pinyin: signal.pinyin,
        sources: signal.sources,
        risk: signal.risk,
        completedAt: new Date().toISOString(),
        score: 100,
      };
      setMissDrillHistory((current) => [
        entry,
        ...current.filter((item) => item.signalId !== signal.id),
      ].slice(0, CHINESE_MISS_DRILL_HISTORY_LIMIT));
      scheduleMissFollowUp(signal, selectedPracticeRecord.day);
      setSessionXp((xp) => xp + (activeMissFollowUpId ? 12 : 18));
      setReviewCombo((combo) => combo + 1);
      setRewardMessage(
        activeMissFollowUpId
          ? `follow-up checked · ${signal.hanzi}`
          : `micro drill locked · ${signal.hanzi} · follow-up queued`,
      );
      setActiveMissFollowUpId("");
      return;
    }

    const stepCopy = chineseMissDrillSteps.find((step) => step.id === stepId);
    setRewardMessage(`${signal.hanzi} ${stepCopy?.title ?? stepId} gate · ${nextDoneCount}/${chineseMissDrillSteps.length}`);
  }

  function logPlacementHistory(profile: ChinesePlacementProfile) {
    const entry: ChinesePlacementHistoryEntry = {
      id: `${Date.now()}-${profile.recommendedDay}-${profile.status}`,
      createdAt: new Date().toISOString(),
      fromDay: selectedPracticeDay,
      toDay: profile.status === "sample" ? selectedPracticeDay : profile.recommendedDay,
      status: profile.status,
      hskLabel: profile.hskLabel,
      readiness: profile.readiness,
      confidence: profile.confidence,
      action: profile.action,
      summary: profile.summary,
    };
    setPlacementHistory((current) => [entry, ...current].slice(0, 21));
  }

  function openPlacementHistoryEntry(entry: ChinesePlacementHistoryEntry) {
    selectPracticeDay(entry.toDay);
    setRewardMessage(
      `placement log loaded · ${entry.hskLabel} · ${entry.readiness}% ready / ${entry.confidence}% conf`,
    );
  }

  function runPlacementCalibration() {
    logPlacementHistory(placementProfile);

    if (placementProfile.status === "sample") {
      setLessonFocusActive(true);
      setRewardMessage("placement sample armed · run listen/build/write/recall");
      return;
    }

    selectPracticeDay(placementProfile.recommendedDay);
    setRewardMessage(
      `placement calibrated · ${placementProfile.hskLabel} · D${String(placementProfile.recommendedDay).padStart(3, "0")}`,
    );
  }

  function stageCoachEvidencePacket() {
    setCoachPacketOpen((current) => !current);
    setRewardMessage(`coach packet staged · ${coachEvidenceChecksum}`);
  }

  async function copyCoachEvidencePacket() {
    try {
      await navigator.clipboard.writeText(coachEvidenceText);
      setRewardMessage(`coach packet copied · ${coachEvidenceChecksum}`);
    } catch {
      setCoachPacketOpen(true);
      setRewardMessage(`coach packet staged · ${coachEvidenceChecksum}`);
    }
  }

  function logCoachBriefing() {
    const entry: ChineseCoachHistoryEntry = {
      id: `${coachEvidencePacket.packetId}:${coachBriefing.mode}:${Date.now()}`,
      createdAt: new Date().toISOString(),
      packetId: coachEvidencePacket.packetId,
      mode: coachBriefing.mode,
      signal: coachBriefing.signal,
      title: coachBriefing.title,
      command: coachBriefing.command,
      day: selectedPracticeRecord.day,
      activeWord: coachEvidencePacket.scope.activeWord,
      baseline: getChineseCoachHistoryBaseline(coachEvidencePacket),
    };
    setCoachHistory((current) => [entry, ...current].slice(0, CHINESE_COACH_HISTORY_LIMIT));
    return entry;
  }

  function openCoachHistoryEntry(entry: ChineseCoachHistoryEntry) {
    selectPracticeDay(entry.day);
    if (entry.activeWord) openDictionary(entry.activeWord);
    setRewardMessage(`coach log loaded · ${entry.signal} · ${entry.packetId}`);
  }

  function applyLoadForecast() {
    selectPracticeDay(loadForecast.recommendedDay);
    setRewardMessage(
      `load forecast applied · D${String(loadForecast.recommendedDay).padStart(3, "0")} · ${loadForecast.label}`,
    );
  }

  function loadReviewFirstCard(card = reviewFirstTarget, openFocus = false) {
    setActiveLessonId(card.lessonId);
    setSelectedPhraseIndex(card.exampleIndex);
    setActiveReviewId(card.id);
    setActiveLessonStep("recall");
    setCardRevealed(true);
    openDictionary(getChinesePhraseUnits(card.hanzi)[0] ?? card.hanzi);
    if (openFocus) setLessonFocusActive(true);
    setRewardMessage(`review-first loaded · ${card.lessonCode} · ${card.hanzi}`);
  }

  function startReviewFirstSession() {
    loadReviewFirstCard(reviewFirstTarget, true);
  }

  function unlockReviewFirstShield() {
    if (!reviewFirstPressureActive) return;
    const entry: ChineseReviewUnlockEntry = {
      id: `${reviewUnlockKey}:${Date.now()}`,
      key: reviewUnlockKey,
      createdAt: new Date().toISOString(),
      day: selectedPracticeRecord.day,
      status: loadForecast.status,
      reviewedCards: reviewUnlockProgress,
      target: reviewUnlockTarget,
      peakLoad: loadForecast.peak.totalLoad,
      summary: `D${String(selectedPracticeRecord.day).padStart(3, "0")} rail restored after ${reviewUnlockProgress}/${reviewUnlockTarget} recall cards.`,
    };
    setReviewUnlocks((current) => [entry, ...current.filter((item) => item.key !== reviewUnlockKey)].slice(0, 21));
    setCardRevealed(false);
    setActiveLessonStep("listen");
    setRewardMessage(`new-word rail restored · ${reviewUnlockProgress}/${reviewUnlockTarget} recalled`);
  }

  function runCoachBriefing() {
    logCoachBriefing();

    if (coachBriefing.mode === "forecast") {
      if (reviewUnlockReady) {
        unlockReviewFirstShield();
      } else {
        startReviewFirstSession();
      }
      return;
    }

    if (coachBriefing.mode === "sample") {
      setLessonFocusActive(true);
      setActiveLessonStep("listen");
      setRewardMessage(`coach briefing armed · ${coachBriefing.signal}`);
      return;
    }

    if (coachBriefing.mode === "repair") {
      loadAdaptiveRepairMission();
      setRewardMessage(`coach briefing armed · ${coachBriefing.signal}`);
      return;
    }

    if (coachBriefing.mode === "review") {
      setActiveReviewId(activeReviewCard.id);
      setActiveLessonStep("recall");
      setRewardMessage(`coach briefing armed · ${coachBriefing.signal}`);
      return;
    }

    if (coachBriefing.mode === "voice") {
      setLessonFocusActive(true);
      setActiveLessonStep("recall");
      setRewardMessage(`coach briefing armed · ${coachBriefing.signal}`);
      return;
    }

    if (coachBriefing.mode === "placement") {
      selectPracticeDay(selectedPracticeRecord.day);
      setRewardMessage(`coach briefing armed · ${coachBriefing.signal}`);
      return;
    }

    runGuidedCircuitStep();
    setRewardMessage(`coach briefing armed · ${coachBriefing.signal}`);
  }

  function toggleRepairDrill(drill: ChineseAdaptiveRepairDrill) {
    const wasDone = completedRepairDrills.has(drill.id);
    setCompletedRepairDrills((current) => {
      const next = new Set(current);
      if (next.has(drill.id)) {
        next.delete(drill.id);
      } else {
        next.add(drill.id);
      }
      return next;
    });
    if (wasDone) {
      if (repairMissionLocked) {
        setRepairHistory((current) => current.filter((entry) => entry.missionKey !== adaptiveRepairMission.key));
      }
      setRewardMessage(`${drill.label} reopened`);
    } else {
      setSessionXp((xp) => xp + CHINESE_REPAIR_DRILL_XP);
      const nextDoneCount = repairDrillDoneCount + 1;
      if (adaptiveRepairMission.hasSignal && nextDoneCount === adaptiveRepairMission.drills.length) {
        const nextHistoryEntry: ChineseRepairHistoryEntry = {
          id: `${adaptiveRepairMission.key}:${Date.now()}`,
          missionKey: adaptiveRepairMission.key,
          completedAt: new Date().toISOString(),
          day: adaptiveRepairMission.targetDay,
          tone: adaptiveRepairMission.tone.tone,
          toneName: adaptiveRepairMission.tone.name,
          symbols: adaptiveRepairMission.symbols.map((symbol) => symbol.hanzi),
          score: 100,
          summary: adaptiveRepairMission.summary,
        };
        setRepairHistory((current) => [
          nextHistoryEntry,
          ...current.filter((entry) => entry.missionKey !== adaptiveRepairMission.key),
        ].slice(0, 21));
        setReviewCombo((combo) => combo + 1);
        setRewardMessage(`repair mission locked · ${adaptiveRepairMission.summary}`);
      } else {
        setRewardMessage(`${CHINESE_REPAIR_DRILL_XP} XP · ${drill.feedback}`);
      }
    }
  }

  function rateReview(rating: ChineseReviewRating, cardId = activeReviewCard.id) {
    const xp = rating === "again" ? 3 : rating === "hard" ? 6 : rating === "ok" ? 10 : 15;
    setReviewRatings((current) => ({
      ...current,
      [cardId]: scheduleChineseReview(current[cardId], rating),
    }));
    setSessionXp((current) => current + xp);
    setReviewCombo((current) => (rating === "again" ? 0 : current + 1));
    setRewardMessage(`${xp} XP · ${rating === "again" ? "repair queued" : rating === "hard" ? "short interval" : rating === "ok" ? "memory strengthened" : "easy recall"}`);
    setActiveLessonStep("recall");
  }

  function gradeActivePhrase(rating: ChineseReviewRating) {
    rateReview(rating, activePhraseReviewId);
    setCardRevealed(false);
    setSelectedPhraseIndex((current) => (current + 1) % activeLesson.examples.length);
  }

  function toggleStrokeStep(id: string) {
    const key = `${activeStrokePrefix}-${id}`;
    setStrokeMatrixDone((current) => {
      const next = new Set(current);
      if (next.has(key)) {
        next.delete(key);
      } else {
        next.add(key);
      }
      return next;
    });
  }

  function runGuidedCircuitStep(stepId = nextCircuitStep.id) {
    const circuitStep = lessonStepStatus.find((step) => step.id === stepId) ?? nextCircuitStep;
    setActiveLessonStep(circuitStep.id);

    if (circuitStep.id === "listen") {
      speakMandarin(activePhrase.hanzi);
      setCompletedDrills((current) => new Set(current).add("listen"));
      setRewardMessage("listen gate locked · tone shadow started");
      return;
    }

    if (circuitStep.id === "meaning") {
      setCardRevealed(true);
      openDictionary(activeDictionaryEntry.hanzi);
      setRewardMessage("meaning gate open · dictionary focused");
      return;
    }

    if (circuitStep.id === "build") {
      const nextTile = assemblyTiles.find((tile) => tile.index === assemblyAttemptUnits.length && !assemblyTileIds.includes(tile.id));
      if (nextTile) {
        selectAssemblyTile(nextTile.id);
        setRewardMessage(`syntax slot ${nextTile.index + 1} locked`);
      } else {
        setRewardMessage("sentence order already locked");
      }
      return;
    }

    if (circuitStep.id === "write") {
      const nextStrokeStep = chineseStrokeMatrixSteps.find((step) => !strokeMatrixDone.has(`${activeStrokePrefix}-${step.id}`));
      if (nextStrokeStep) {
        toggleStrokeStep(nextStrokeStep.id);
        setRewardMessage(`${nextStrokeStep.label} stroke pass locked`);
      } else {
        setRewardMessage("stroke matrix already complete");
      }
      return;
    }

    gradeActivePhrase("ok");
  }

  function startSpeechGate() {
    if (speechStatus === "listening") return;

    const speechWindow = window as typeof window & {
      SpeechRecognition?: new () => ChineseSpeechRecognition;
      webkitSpeechRecognition?: new () => ChineseSpeechRecognition;
    };
    const SpeechRecognitionConstructor = speechWindow.SpeechRecognition ?? speechWindow.webkitSpeechRecognition;

    if (!SpeechRecognitionConstructor) {
      setSpeechStatus("unsupported");
      setSpeechTranscript("Speech recognition is not available in this browser.");
      setSpeechScore(0);
      setSpeechConfidence(0);
      setRewardMessage("voice gate offline · browser unsupported");
      return;
    }

    const recognition = new SpeechRecognitionConstructor();
    recognition.lang = "zh-CN";
    recognition.interimResults = false;
    recognition.maxAlternatives = 1;
    setSpeechStatus("listening");
    setSpeechTranscript("");
    setSpeechScore(0);
    setSpeechConfidence(0);
    setRewardMessage("voice gate listening · speak the active sentence");

    recognition.onresult = (event) => {
      const result = event.results[0]?.[0];
      const transcript = result?.transcript?.trim() ?? "";
      const confidence = Math.round((result?.confidence ?? 0) * 100);
      const scored = scoreChineseSpeech(activePhrase.hanzi, transcript);
      const rating: ChineseReviewRating | null = scored.score >= 88 ? "easy" : scored.score >= 70 ? "ok" : scored.score >= 45 ? "hard" : null;
      const attempt: ChineseSpeechAttempt = {
        id: `${activePhraseReviewId}-${Date.now()}`,
        cardId: activePhraseReviewId,
        phrase: activePhrase.hanzi,
        transcript: transcript || "No Mandarin phrase captured.",
        score: scored.score,
        confidence,
        matched: scored.matched,
        total: scored.total,
        createdAt: new Date().toISOString(),
        rating: rating ?? undefined,
      };

      setSpeechTranscript(transcript || "No Mandarin phrase captured.");
      setSpeechScore(scored.score);
      setSpeechConfidence(confidence);
      setSpeechStatus("scored");
      setSpeechAttempts((current) => [attempt, ...current].slice(0, CHINESE_SPEECH_HISTORY_LIMIT));

      if (rating) {
        rateReview(rating, activePhraseReviewId);
        setRewardMessage(`voice ${scored.score}% · ${rating} recall scheduled`);
      } else {
        setRewardMessage(`voice ${scored.score}% · repeat the phrase`);
      }
    };

    recognition.onerror = () => {
      setSpeechStatus("error");
      setSpeechTranscript("Voice capture failed. Try again.");
      setRewardMessage("voice gate interrupted");
    };

    recognition.onend = () => {
      setSpeechStatus((current) => (current === "listening" ? "idle" : current));
    };

    recognition.start();
  }

  function speakMandarin(text: string) {
    if (!("speechSynthesis" in window)) return;
    const utterance = new SpeechSynthesisUtterance(text);
    utterance.lang = "zh-CN";
    utterance.rate = 0.82;
    utterance.pitch = 1;
    window.speechSynthesis.cancel();
    window.speechSynthesis.speak(utterance);
  }

