const promptReviewGrades: Array<{ id: PromptReviewGrade; label: string; effect: string }> = [
  { id: "again", label: "Again", effect: "1d" },
  { id: "hard", label: "Hard", effect: "short" },
  { id: "good", label: "Good", effect: "grow" },
  { id: "easy", label: "Easy", effect: "boost" },
];

function getDefaultPromptReviewStates(day = 1): Record<string, PromptReviewState> {
  return promptTheoryQuestions.reduce<Record<string, PromptReviewState>>((states, question, index) => {
    states[question.id] = {
      dueDay: index < 3 ? day : Math.min(90, day + index),
      interval: 1,
      ease: 2.4,
      reps: 0,
      lapses: 0,
    };
    return states;
  }, {});
}

function getEmptyPromptTaskJournal(taskId: string): PromptTaskJournal {
  return {
    taskId,
    answer: "",
    selfScore: 70,
    versionNote: "",
    savedAt: "",
    history: [],
  };
}

function isPromptTaskJournal(value: unknown): value is PromptTaskJournal {
  return Boolean(value && typeof value === "object" && "taskId" in value && "answer" in value);
}

function clampPromptPercent(value: unknown) {
  const numeric = Number(value);
  return Number.isFinite(numeric) ? Math.min(100, Math.max(0, Math.round(numeric))) : 0;
}

function normalizePromptMasteryHistoryEntry(value: unknown): PromptMasteryHistoryEntry | null {
  if (!value || typeof value !== "object") return null;
  const record = value as Partial<PromptMasteryHistoryEntry>;
  const day = Math.min(Math.max(Math.trunc(Number(record.day) || 1), 1), 90);
  const score = clampPromptPercent(record.score);
  const savedAt = typeof record.savedAt === "string" && record.savedAt ? record.savedAt : "";
  if (!savedAt) return null;
  return {
    day,
    score,
    label: typeof record.label === "string" && record.label ? record.label : getPromptMasteryLabel(score),
    taskCompletion: clampPromptPercent(record.taskCompletion),
    journalCompletion: clampPromptPercent(record.journalCompletion),
    coachScore: clampPromptPercent(record.coachScore),
    srsReadiness: clampPromptPercent(record.srsReadiness),
    playgroundScore: clampPromptPercent(record.playgroundScore),
    nextAction: typeof record.nextAction === "string" && record.nextAction ? record.nextAction : "Review the weakest signal and lock a new checkpoint.",
    savedAt,
  };
}

function normalizePromptRedTeamReplayEntry(value: unknown): PromptRedTeamReplayEntry | null {
  if (!value || typeof value !== "object") return null;
  const record = value as Partial<PromptRedTeamReplayEntry>;
  const id = typeof record.id === "string" && record.id ? record.id : "";
  const taskId = typeof record.taskId === "string" && record.taskId ? record.taskId : "";
  const savedAt = typeof record.savedAt === "string" && record.savedAt ? record.savedAt : "";
  if (!id || !taskId || !savedAt) return null;
  return {
    id,
    taskId,
    day: Math.min(Math.max(Math.trunc(Number(record.day) || 1), 1), 90),
    packetId: typeof record.packetId === "string" ? record.packetId : "",
    versionNote: typeof record.versionNote === "string" ? record.versionNote : "red-team replay",
    savedAt,
    rewriteScore: clampPromptPercent(record.rewriteScore),
    stressScore: clampPromptPercent(record.stressScore),
    adversaryScore: clampPromptPercent(record.adversaryScore),
    combinedScore: clampPromptPercent(record.combinedScore),
    weakestStress: typeof record.weakestStress === "string" ? record.weakestStress : "not recorded",
    weakestAdversary: typeof record.weakestAdversary === "string" ? record.weakestAdversary : "not recorded",
    verdict: typeof record.verdict === "string" ? record.verdict : "replay recorded",
  };
}

function normalizePromptIncidentReportArchiveEntry(value: unknown): PromptIncidentReportArchiveEntry | null {
  if (!value || typeof value !== "object") return null;
  const record = value as Partial<PromptIncidentReportArchiveEntry>;
  const id = typeof record.id === "string" && record.id ? record.id : "";
  const taskId = typeof record.taskId === "string" && record.taskId ? record.taskId : "";
  const reportId = typeof record.reportId === "string" && record.reportId ? record.reportId : "";
  const savedAt = typeof record.savedAt === "string" && record.savedAt ? record.savedAt : "";
  const markdown = typeof record.markdown === "string" ? record.markdown : "";
  if (!id || !taskId || !reportId || !savedAt || !markdown) return null;
  const searchText = typeof record.searchText === "string" && record.searchText
    ? record.searchText
    : `${record.reportId ?? ""} ${record.scenarioTitle ?? ""} ${record.verdict ?? ""} ${record.weakestStress ?? ""} ${record.weakestAdversary ?? ""} ${markdown}`.toLowerCase();
  return {
    id,
    taskId,
    day: Math.min(Math.max(Math.trunc(Number(record.day) || 1), 1), 90),
    reportId,
    packetId: typeof record.packetId === "string" ? record.packetId : "",
    scenarioTitle: typeof record.scenarioTitle === "string" ? record.scenarioTitle : "scenario not recorded",
    savedAt,
    readinessScore: clampPromptPercent(record.readinessScore),
    verdict: typeof record.verdict === "string" ? record.verdict : "report archived",
    versionNote: typeof record.versionNote === "string" ? record.versionNote : "incident report",
    weakestStress: typeof record.weakestStress === "string" ? record.weakestStress : "not recorded",
    weakestAdversary: typeof record.weakestAdversary === "string" ? record.weakestAdversary : "not recorded",
    replayMovement: Number.isFinite(Number(record.replayMovement)) ? Math.round(Number(record.replayMovement)) : 0,
    markdown,
    searchText,
  };
}

function normalizePromptMentorRehearsalAttempt(value: unknown): PromptMentorRehearsalAttempt | null {
  if (!value || typeof value !== "object") return null;
  const record = value as Partial<PromptMentorRehearsalAttempt>;
  const id = typeof record.id === "string" && record.id ? record.id : "";
  const taskId = typeof record.taskId === "string" && record.taskId ? record.taskId : "";
  const targetId = typeof record.targetId === "string" && record.targetId ? record.targetId : "";
  const questionId = typeof record.questionId === "string" && record.questionId ? record.questionId : "";
  const savedAt = typeof record.savedAt === "string" && record.savedAt ? record.savedAt : "";
  const answer = typeof record.answer === "string" ? record.answer : "";
  if (!id || !taskId || !targetId || !questionId || !savedAt || !answer.trim()) return null;
  const selfScore = clampPromptPercent(record.selfScore);
  return {
    id,
    taskId,
    targetId,
    questionId,
    questionLabel: typeof record.questionLabel === "string" && record.questionLabel ? record.questionLabel : "mentor question",
    answer,
    selfScore,
    durationSeconds: Math.min(600, Math.max(15, Math.trunc(Number(record.durationSeconds) || 90))),
    verdict: typeof record.verdict === "string" && record.verdict ? record.verdict : getPromptMentorRehearsalVerdict(selfScore),
    savedAt,
  };
}

