  const [defenseRehearsalAnswer, setDefenseRehearsalAnswer] = useState("");
  const [defenseRehearsalSelfScore, setDefenseRehearsalSelfScore] = useState(72);
  const [reviewCheckpointDay, setReviewCheckpointDay] = useState<number | null>(null);
  const queuedDefenseRehearsalRef = useRef<{ questionId: string; answer: string; seconds: number; score: number } | null>(null);

  const dailyTasks = useMemo(() => getPromptDailyTasks(selectedDay), [selectedDay]);
  const activeDailyTask = dailyTasks.find((task) => task.id === activeDailyTaskId) ?? dailyTasks[0];
  const activeTaskJournal = taskJournals[activeDailyTask.id] ?? getEmptyPromptTaskJournal(activeDailyTask.id);
  const activeTaskFeedback = useMemo(
    () => buildTaskJournalFeedback(activeTaskJournal.answer, activeDailyTask.label),
    [activeDailyTask.label, activeTaskJournal.answer],
  );
  const activeEvidencePacket = useMemo(() => buildPromptEvidencePacket(activeDailyTask), [activeDailyTask]);
  const activeEvidencePacketPrompt = useMemo(
    () => buildPromptEvidencePacketPrompt(activeEvidencePacket, activeDailyTask),
    [activeDailyTask, activeEvidencePacket],
  );
  const evidencePromptSource = activeTaskJournal.answer.trim() || playgroundPrompt;
  const activeEvidenceGrade = useMemo(
    () => gradePromptAgainstEvidencePacket(evidencePromptSource, activeEvidencePacket),
    [activeEvidencePacket, evidencePromptSource],
  );
  const activeEvidenceDiff = useMemo(
    () => buildPromptEvidencePacketDiff(evidencePromptSource, activeEvidencePacket),
    [activeEvidencePacket, evidencePromptSource],
  );
  const activeEvidenceRewrite = useMemo(
    () => buildPromptPacketSafeRewrite({
      prompt: evidencePromptSource,
      diff: activeEvidenceDiff,
      packet: activeEvidencePacket,
      task: activeDailyTask,
    }),
    [activeDailyTask, activeEvidenceDiff, activeEvidencePacket, evidencePromptSource],
  );
  const activeStressHarness = useMemo(
    () => buildPromptEvidenceStressHarness(activeEvidencePacket, activeEvidenceRewrite),
    [activeEvidencePacket, activeEvidenceRewrite],
  );
  const activeAdversaryHarness = useMemo(
    () => buildPromptEvidenceAdversaryHarness(activeEvidencePacket, activeEvidenceRewrite),
    [activeEvidencePacket, activeEvidenceRewrite],
  );
  const activeReplayHistory = useMemo(
    () => redTeamReplayHistory.filter((entry) => entry.taskId === activeDailyTask.id).slice(0, 6),
    [activeDailyTask.id, redTeamReplayHistory],
  );
  const replayImprovement = activeReplayHistory.length >= 2 ? activeReplayHistory[0].combinedScore - activeReplayHistory[1].combinedScore : 0;
  const activeIncidentReport = useMemo(
    () => buildPromptIncidentReport({
      day: selectedDay,
      task: activeDailyTask,
      packet: activeEvidencePacket,
      grade: activeEvidenceGrade,
      diff: activeEvidenceDiff,
      rewrite: activeEvidenceRewrite,
      stress: activeStressHarness,
      adversary: activeAdversaryHarness,
      replayHistory: activeReplayHistory,
      journal: activeTaskJournal,
    }),
    [
      activeAdversaryHarness,
      activeDailyTask,
      activeEvidenceDiff,
      activeEvidenceGrade,
      activeEvidencePacket,
      activeEvidenceRewrite,
      activeReplayHistory,
      activeStressHarness,
      activeTaskJournal,
      selectedDay,
    ],
  );
  const activeReportArchive = useMemo(
    () => incidentReportArchive.filter((entry) => entry.taskId === activeDailyTask.id).slice(0, 6),
    [activeDailyTask.id, incidentReportArchive],
  );
  const filteredIncidentReports = useMemo(() => {
    const tokens = reportArchiveQuery.toLowerCase().split(/\s+/).filter(Boolean);
    const reports = tokens.length
      ? incidentReportArchive.filter((entry) => tokens.every((token) => entry.searchText.includes(token)))
      : incidentReportArchive;
    return reports.slice(0, 8);
  }, [incidentReportArchive, reportArchiveQuery]);
  const reportArchiveStats = useMemo(() => {
    const averageReadiness = average(incidentReportArchive.map((entry) => entry.readinessScore));
    const best = incidentReportArchive.reduce<PromptIncidentReportArchiveEntry | null>(
      (currentBest, entry) => (!currentBest || entry.readinessScore > currentBest.readinessScore ? entry : currentBest),
      null,
    );
    const latest = incidentReportArchive[0] ?? null;
    const priorSameTask = activeReportArchive[1] ?? null;
    const activeScoreDelta = activeReportArchive[0] && priorSameTask ? activeReportArchive[0].readinessScore - priorSameTask.readinessScore : 0;
    return {
      averageReadiness,
      best,
      latest,
      activeScoreDelta,
      count: incidentReportArchive.length,
    };
  }, [activeReportArchive, incidentReportArchive]);
  const activeReportReview = useMemo(
    () => buildPromptReportPortfolioReview({
      report: activeIncidentReport,
      grade: activeEvidenceGrade,
      diff: activeEvidenceDiff,
      stress: activeStressHarness,
      adversary: activeAdversaryHarness,
      archive: activeReportArchive,
      replayHistory: activeReplayHistory,
    }),
    [
      activeAdversaryHarness,
      activeEvidenceDiff,
      activeEvidenceGrade,
      activeIncidentReport,
      activeReportArchive,
      activeReplayHistory,
      activeStressHarness,
    ],
  );
  const activePortfolioExport = useMemo(
    () => buildPromptPortfolioExportPacket({
      day: selectedDay,
      task: activeDailyTask,
      packet: activeEvidencePacket,
      report: activeIncidentReport,
      review: activeReportReview,
      rewrite: activeEvidenceRewrite,
      stress: activeStressHarness,
      adversary: activeAdversaryHarness,
      archive: activeReportArchive,
      journal: activeTaskJournal,
    }),
    [
      activeAdversaryHarness,
      activeDailyTask,
      activeEvidencePacket,
      activeEvidenceRewrite,
      activeIncidentReport,
      activeReportArchive,
      activeReportReview,
      activeStressHarness,
      activeTaskJournal,
      selectedDay,
    ],
  );
  const portfolioGallery = useMemo(
    () => buildPromptPortfolioGallery({
      activeExport: activePortfolioExport,
      activeTask: activeDailyTask,
      selectedDay,
      archive: incidentReportArchive,
      review: activeReportReview,
      mentorRehearsals,
      defenseCalendarSchedules,
      defensePerformanceExports,
    }),
    [activeDailyTask, activePortfolioExport, activeReportReview, defenseCalendarSchedules, defensePerformanceExports, incidentReportArchive, mentorRehearsals, selectedDay],
  );
  const selectedPortfolioPolishTarget = useMemo(
    () => portfolioGallery.items.find((item) => item.id === selectedPortfolioPolishId) ?? portfolioGallery.polishTarget,
    [portfolioGallery, selectedPortfolioPolishId],
  );
  const portfolioPolishWorkflow = useMemo(
    () => buildPromptPortfolioPolishWorkflow({
      target: selectedPortfolioPolishTarget,
      review: activeReportReview,
    }),
    [activeReportReview, selectedPortfolioPolishTarget],
  );
  const activePolishStep = portfolioPolishWorkflow.steps.find((step) => step.id === activePolishStepId) ?? portfolioPolishWorkflow.steps[0];
  const mentorDefenseSimulator = useMemo(
    () => buildPromptMentorDefenseSimulator({
      target: selectedPortfolioPolishTarget,
      review: activeReportReview,
      polish: portfolioPolishWorkflow,
    }),
    [activeReportReview, portfolioPolishWorkflow, selectedPortfolioPolishTarget],
  );
  const activeDefenseQuestion = mentorDefenseSimulator.questions.find((question) => question.id === activeDefenseQuestionId) ?? mentorDefenseSimulator.questions[0];
  const mentorTargetRehearsals = useMemo(
    () =>
      mentorRehearsals.filter(
        (attempt) => attempt.taskId === activeDailyTask.id && attempt.targetId === mentorDefenseSimulator.target.id,
      ),
    [activeDailyTask.id, mentorDefenseSimulator.target.id, mentorRehearsals],
  );
  const defenseAnswerTemplate = useMemo(
    () => buildPromptMentorAnswerTemplate(activeDefenseQuestion, mentorDefenseSimulator.target),
    [activeDefenseQuestion, mentorDefenseSimulator.target],
  );
  const defenseRehearsalCoaching = useMemo(
    () => buildPromptMentorRehearsalCoaching(defenseRehearsalAnswer, activeDefenseQuestion),
    [activeDefenseQuestion, defenseRehearsalAnswer],
  );
  const activeDefenseRehearsals = useMemo(
    () =>
      mentorTargetRehearsals
        .filter((attempt) => attempt.questionId === activeDefenseQuestion.id)
        .slice(0, 3),
    [activeDefenseQuestion.id, mentorTargetRehearsals],
  );
  const mentorRehearsalTrend = useMemo(
    () =>
      buildPromptMentorRehearsalTrend({
        attempts: mentorTargetRehearsals,
        questions: mentorDefenseSimulator.questions,
        target: mentorDefenseSimulator.target,
      }),
    [mentorDefenseSimulator.questions, mentorDefenseSimulator.target, mentorTargetRehearsals],
  );
  const mentorInterruptionSimulator = useMemo(
    () => buildPromptMentorInterruptionSimulator({
      comparison: portfolioGallery.defensePerformanceComparison,
      questions: mentorDefenseSimulator.questions,
      activeQuestion: activeDefenseQuestion,
      target: mentorDefenseSimulator.target,
    }),
    [activeDefenseQuestion, mentorDefenseSimulator.questions, mentorDefenseSimulator.target, portfolioGallery.defensePerformanceComparison],
  );
  const dayMastery = useMemo(
    () => buildPromptDayMasterySnapshot({ day: selectedDay, completedTasks, taskJournals, reviewStates, playgroundPrompt, iterations }),
    [completedTasks, iterations, playgroundPrompt, reviewStates, selectedDay, taskJournals],
  );
  const masteryHistoryByDay = useMemo(() => new Map(masteryHistory.map((entry) => [entry.day, entry])), [masteryHistory]);
  const lockedMastery = masteryHistoryByDay.get(selectedDay);
  const masteryTrend = useMemo(
    () => {
      const trendStart = Math.min(Math.max(1, selectedDay - 6), 84);
      return Array.from({ length: 7 }, (_, index): PromptMasteryTrendPoint => {
        const day = trendStart + index;
        const locked = masteryHistoryByDay.get(day);
        if (locked) return { ...locked, status: "locked" };
        if (day === selectedDay) return { ...dayMastery, status: "draft" };
        return {
          day,
          score: 0,
          label: "not locked",
          taskCompletion: 0,
          journalCompletion: 0,
          coachScore: 0,
          srsReadiness: 0,
          playgroundScore: 0,
          nextAction: "No locked checkpoint exists for this day yet.",
          status: "empty",
        };
      });
    },
    [dayMastery, masteryHistoryByDay, selectedDay],
  );
  const masteryHistoryStats = useMemo(
    () => {
      const best = masteryHistory.reduce<PromptMasteryHistoryEntry | null>(
        (currentBest, entry) => (!currentBest || entry.score > currentBest.score ? entry : currentBest),
        null,
      );
      const latest = [...masteryHistory].sort((a, b) => b.savedAt.localeCompare(a.savedAt))[0] ?? null;
      return {
        averageScore: average(masteryHistory.map((entry) => entry.score)),
        best,
        latest,
        lockedCount: masteryHistory.length,
      };
    },
    [masteryHistory],
  );
  const activeCheckpointReview = useMemo(() => {
    if (reviewCheckpointDay === null) return null;
    const checkpoint = masteryHistoryByDay.get(reviewCheckpointDay) ?? null;
    return checkpoint ? buildPromptCheckpointReview({ checkpoint, completedTasks, taskJournals }) : null;
  }, [completedTasks, masteryHistoryByDay, reviewCheckpointDay, taskJournals]);
  const activeCheckpointAttemptCount = activeCheckpointReview?.attempts.length ?? 0;
  const checkpointComparison = useMemo(
    () => buildPromptCheckpointComparison({ masteryHistory, completedTasks, taskJournals }),
    [completedTasks, masteryHistory, taskJournals],
  );
  const activeDrill = promptDrills.find((drill) => drill.id === activeDrillId) ?? promptDrills[0];
  const activeConcept = promptFoundationConcepts.find((concept) => concept.id === activeConceptId) ?? promptFoundationConcepts[0];
  const activeMistake = promptMistakePatterns.find((mistake) => mistake.id === activeMistakeId) ?? promptMistakePatterns[0];
  const activeSkill = promptSkillLevels.find((level) => level.level === activeSkillLevel) ?? promptSkillLevels[0];
  const activeReference = promptReferenceSheets.find((sheet) => sheet.id === activeReferenceId) ?? promptReferenceSheets[0];
  const activeScenario = promptScenarios.find((scenario) => scenario.id === activeScenarioId) ?? promptScenarios[0];
  const dueQuestions = promptTheoryQuestions
    .map((question) => ({ question, state: reviewStates[question.id] ?? getDefaultPromptReviewStates(selectedDay)[question.id] }))
    .sort((a, b) => a.state.dueDay - b.state.dueDay || b.question.level - a.question.level);
  const activeReview = dueQuestions.find((item) => item.state.dueDay <= selectedDay) ?? dueQuestions[0];
  const completedToday = dailyTasks.filter((task) => completedTasks.has(task.id)).length;
  const dailyProgress = Math.round((completedToday / Math.max(dailyTasks.length, 1)) * 100);
  const dueCount = dueQuestions.filter((item) => item.state.dueDay <= selectedDay).length;
  const retainedCount = dueQuestions.filter((item) => item.state.reps >= 2 && item.state.lapses === 0).length;
  const phaseProgress = Math.round((selectedDay / 90) * 100);
  const activePhase = promptMasteryPhases.find((phase) => selectedDay <= phase.days) ?? promptMasteryPhases[0];
  const activeIterations = iterations.filter((iteration) => iteration.drillId === activeDrill.id).slice(0, 3);
  const promptEndpoint = PROMPT_LAB_ENDPOINT;

  useEffect(() => {
    const saved = savePromptMemorySnapshot({
      selectedDay,
      completedTasks: Array.from(completedTasks).sort(),
      reviewStates,
      iterations: iterations.slice(0, 36),
      taskJournals,
      masteryHistory,
      redTeamReplayHistory,
      incidentReportArchive,
      mentorRehearsals,
      defenseCalendarSchedules,
      defensePerformanceExports,
      playgroundPrompt,
      playgroundOutput,
    });
    if (!saved) setPlaygroundStatus("memory offline");
  }, [completedTasks, defenseCalendarSchedules, defensePerformanceExports, incidentReportArchive, iterations, masteryHistory, mentorRehearsals, playgroundOutput, playgroundPrompt, promptEndpoint, redTeamReplayHistory, reviewStates, selectedDay, taskJournals]);

  useEffect(() => {
    setActiveDailyTaskId((current) => (dailyTasks.some((task) => task.id === current) ? current : dailyTasks[0]?.id ?? current));
  }, [dailyTasks]);

  useEffect(() => {
    setActiveDailyPanel("mission");
  }, [activeDailyTaskId]);

  useEffect(() => {
    const queued = queuedDefenseRehearsalRef.current;
    if (queued?.questionId === activeDefenseQuestion.id) {
      queuedDefenseRehearsalRef.current = null;
      setDefenseRehearsalRunning(false);
      setDefenseRehearsalSeconds(queued.seconds);
      setDefenseRehearsalTimebox(queued.seconds);
      setDefenseRehearsalAnswer(queued.answer);
      setDefenseRehearsalSelfScore(queued.score);
      return;
    }
    setDefenseRehearsalRunning(false);
    setDefenseRehearsalSeconds(90);
    setDefenseRehearsalTimebox(90);
    setDefenseRehearsalAnswer(buildPromptMentorAnswerTemplate(activeDefenseQuestion, mentorDefenseSimulator.target));
    setDefenseRehearsalSelfScore(Math.min(92, Math.max(62, Math.round(activeDefenseQuestion.score))));
  }, [activeDefenseQuestion, mentorDefenseSimulator.target]);

  useEffect(() => {
    if (!defenseRehearsalRunning) return undefined;
    const timer = window.setInterval(() => {
      setDefenseRehearsalSeconds((seconds) => {
        if (seconds <= 1) {
          window.clearInterval(timer);
          setDefenseRehearsalRunning(false);
          setPlaygroundStatus("mentor-defense timer complete");
          return 0;
        }
        return seconds - 1;
      });
    }, 1000);
    return () => window.clearInterval(timer);
  }, [defenseRehearsalRunning]);

  function toggleDailyTask(taskId: string) {
    setCompletedTasks((current) => {
      const next = new Set(current);
      if (next.has(taskId)) next.delete(taskId);
      else next.add(taskId);
      return next;
    });
  }

  function lockMasterySnapshot() {
    const savedAt = new Date().toISOString();
    setMasteryHistory((current) =>
      [
        ...current.filter((entry) => entry.day !== selectedDay),
        {
          ...dayMastery,
          savedAt,
        },
      ].sort((a, b) => a.day - b.day).slice(-90),
    );
    setReviewCheckpointDay(selectedDay);
    setPlaygroundStatus(`D${String(selectedDay).padStart(2, "0")} mastery checkpoint locked`);
  }

  function loadCheckpointDrill(task: PromptDailyTask) {
    const dayMatch = task.id.match(/^d(\d+)-/);
    if (dayMatch) setSelectedDay(Number(dayMatch[1]));
    setActiveDailyTaskId(task.id);
    setActiveDailyPanel("journal");
    setPlaygroundPrompt(task.template);
    setPlaygroundStatus(`checkpoint drill loaded: ${task.label}`);
  }

  function loadEvidencePacketIntoLab() {
    setPlaygroundPrompt(activeEvidencePacketPrompt);
    setPlaygroundStatus(`evidence packet staged: ${activeEvidencePacket.packetId}`);
  }

  function loadEvidencePacketIntoJournal() {
    updateTaskJournal({
      answer: activeEvidencePacketPrompt,
      versionNote: `packet scaffold ${activeEvidencePacket.packetId}`,
    });
    setActiveDailyPanel("journal");
    setPlaygroundStatus(`evidence packet journaled: ${activeEvidencePacket.packetId}`);
  }

  function loadEvidenceDiffRepairIntoJournal() {
    const repairPrompt = buildPromptEvidenceDiffRepairPrompt(activeEvidenceDiff, activeEvidencePacket, activeDailyTask);
    const currentAnswer = activeTaskJournal.answer.trim();
    updateTaskJournal({
      answer: currentAnswer ? `${currentAnswer}\n\n---\n${repairPrompt}` : repairPrompt,
      versionNote: `diff repair ${activeEvidencePacket.packetId}`,
    });
    setActiveDailyPanel("journal");
    setPlaygroundStatus(`packet diff repair loaded: ${activeEvidencePacket.packetId}`);
  }

  function applyEvidenceRewriteToJournal() {
    updateTaskJournal({
      answer: activeEvidenceRewrite.afterPrompt,
      selfScore: Math.max(activeTaskJournal.selfScore, activeEvidenceRewrite.afterScore),
      versionNote: `packet-safe v2 ${activeEvidencePacket.packetId}`,
    });
    setPlaygroundPrompt(activeEvidenceRewrite.afterPrompt);
    setActiveDailyPanel("journal");
    setPlaygroundStatus(`packet-safe rewrite applied: +${Math.max(0, activeEvidenceRewrite.scoreDelta)} signal`);
  }

  function previewEvidenceRewriteInLab() {
    setPlaygroundPrompt(activeEvidenceRewrite.afterPrompt);
    setActiveDailyPanel("lab");
    setPlaygroundStatus(`packet-safe v2 staged: ${activeEvidencePacket.packetId}`);
  }

  function loadWeakestStressCaseIntoLab() {
    setPlaygroundPrompt(activeStressHarness.weakest.stressPrompt);
    setActiveDailyPanel("lab");
    setPlaygroundStatus(`stress case staged: ${activeStressHarness.weakest.label}`);
  }

  function applyStressHardenedRewriteToJournal() {
    const hardenedPrompt = buildPromptStressHardenedRewrite(activeEvidenceRewrite, activeStressHarness);
    updateTaskJournal({
      answer: hardenedPrompt,
      selfScore: Math.max(activeTaskJournal.selfScore, activeStressHarness.averageScore),
      versionNote: `stress-hardened v3 ${activeEvidencePacket.packetId}`,
    });
    setPlaygroundPrompt(hardenedPrompt);
    setActiveDailyPanel("journal");
    setPlaygroundStatus(`stress-hardened rewrite applied: ${activeStressHarness.averageScore}/100`);
  }

  function loadWeakestAdversaryCaseIntoLab() {
    setPlaygroundPrompt(activeAdversaryHarness.weakest.adversaryPrompt);
    setActiveDailyPanel("lab");
    setPlaygroundStatus(`adversary case staged: ${activeAdversaryHarness.weakest.label}`);
  }

  function applyAdversaryHardenedRewriteToJournal() {
    const hardenedPrompt = buildPromptAdversaryHardenedRewrite(activeEvidenceRewrite, activeAdversaryHarness);
    updateTaskJournal({
      answer: hardenedPrompt,
      selfScore: Math.max(activeTaskJournal.selfScore, activeAdversaryHarness.averageScore),
      versionNote: `adversary-hardened v4 ${activeEvidencePacket.packetId}`,
    });
    setPlaygroundPrompt(hardenedPrompt);
    setActiveDailyPanel("journal");
    setPlaygroundStatus(`adversary-hardened rewrite applied: ${activeAdversaryHarness.averageScore}/100`);
  }

  function saveRedTeamReplay() {
    const entry = buildPromptRedTeamReplayEntry({
      day: selectedDay,
      task: activeDailyTask,
      packet: activeEvidencePacket,
      rewrite: activeEvidenceRewrite,
      stress: activeStressHarness,
      adversary: activeAdversaryHarness,
      versionNote: activeTaskJournal.versionNote || activeEvidenceRewrite.verdict,
    });
    setRedTeamReplayHistory((current) => [entry, ...current.filter((item) => item.id !== entry.id)].slice(0, 60));
    setPlaygroundStatus(`red-team replay saved: ${entry.combinedScore}/100`);
  }

  function loadReplayWeaknessIntoJournal(entry: PromptRedTeamReplayEntry) {
    updateTaskJournal({
      answer: [
        activeTaskJournal.answer.trim() || activeEvidenceRewrite.afterPrompt,
        "",
        "Replay repair focus:",
        `- Prior verdict: ${entry.verdict} (${entry.combinedScore}/100).`,
        `- Weakest stress case: ${entry.weakestStress}.`,
        `- Weakest adversary case: ${entry.weakestAdversary}.`,
        "- Revise the prompt so the weakest cases improve without removing schema, confidence, missing-data disclosure, or approval gates.",
      ].join("\n"),
      versionNote: `replay repair ${entry.combinedScore}/100`,
    });
    setActiveDailyPanel("journal");
    setPlaygroundStatus(`replay repair loaded: ${entry.verdict}`);
  }

  async function copyIncidentReport() {
    try {
      await navigator.clipboard.writeText(activeIncidentReport.markdown);
      setPlaygroundStatus(`incident report copied: ${activeIncidentReport.reportId}`);
    } catch {
      setPlaygroundOutput(activeIncidentReport.markdown);
      setPlaygroundStatus("copy blocked; report staged in output panel");
    }
  }

  function stageIncidentReportInLab() {
    setPlaygroundPrompt(activeIncidentReport.markdown);
    setActiveDailyPanel("lab");
    setPlaygroundStatus(`incident report staged: ${activeIncidentReport.readinessScore}/100`);
  }

  function saveIncidentReportToJournal() {
    const currentAnswer = activeTaskJournal.answer.trim() || activeEvidenceRewrite.afterPrompt;
    updateTaskJournal({
      answer: `${currentAnswer}\n\n---\n${activeIncidentReport.markdown}`,
      selfScore: Math.max(activeTaskJournal.selfScore, activeIncidentReport.readinessScore),
      versionNote: `incident report ${activeIncidentReport.reportId}`,
    });
    setActiveDailyPanel("journal");
    setPlaygroundStatus(`incident report journaled: ${activeIncidentReport.verdict}`);
  }

